const coverScreen = document.getElementById('cover-screen');
const textScreen = document.getElementById('text-screen');
const glitchText = document.getElementById('glitch-text');
const finalScreen = document.getElementById('final-screen');
const titleScreen = document.getElementById('title-screen');
const contentsScreen = document.getElementById('contents-screen');
const chapterScreen = document.getElementById('chapter-screen');

let isStarted = false;
let currentChapter = 0;

const STORAGE_KEY = 'echo_state';

function loadState() {
    try { return JSON.parse(localStorage.getItem(STORAGE_KEY)) || {}; }
    catch (e) { return {}; }
}
function saveState(patch) {
    const s = loadState();
    Object.assign(s, patch);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(s));
}
const state = loadState();

// === ТЕКСТЫ ГЛАВ (готовые) ===
const chapterTexts = {
    0: `<p>В начале была метель.</p>
<p>Я разглядывал двор, в котором мне предстояло жить. Обычная панельная девятиэтажка, по бокам и напротив — её копии. Вместе они создавали иллюзию дома-колодца. Только панельного. Во дворе беседка, качели, турники. Дальше виднелся декор, созданный из старых покрышек: они покрашены и наполовину вкопаны в землю.</p>
<p>— Ярослав, соберись, что ты зеваешь по сторонам, — прервал мои размышления голос отца. — Мы так и до вечера не управимся.</p>
<p>— Да я просто логистику оцениваю, пап, — улыбнулся я, стараясь пошутить его терминами. — Смотри, вон в том месте будет удобнее разгружать вещи. Ну, где-то на 27 процентов.</p>
<p>Я встретился с усталым взглядом отца.</p>
<p>— Не умничай, пожалуйста. Просто делай. У нас и так это уже всё много времени заняло, — отрезал он.</p>
<p>Улыбка сошла с моего лица.</p>
<p>Отец направился к грузовику. На нём перевезли наши вещи. Сами же мы доехали поездом сегодня утром, 2 апреля 2007 года. Москва — Волгоград. Отцу предложили повышение в проектном институте, требовалось поднять уровень филиалов по югу страны. Огромное признание, большая прибавка и, главное, возможность развития. По крайней мере, так говорил отец.</p>
<p>Мы перетаскивали вещи из грузовика в подъезд, там вызывали лифт, грузового не было, только пассажирский, поэтому за раз много не поднимешь, и заносили в квартиру. Так цикл за циклом, пока не осталась последняя небольшая коробка с моими вещами. Я взял её, водитель закрыл грузовик и попрощался с нами. Мы пошли с отцом в новый дом.</p>
<p>— Мать завтра дойдёт до школы, тебя оформят. Надо будет физмат, тебе нужно готовиться усерднее, — сказал отец, пока мы ждали лифт.</p>
<p>— Пап, но я не… Что если не справлюсь? Тем более, если учителя другие, другая подготовка, школа, уровень.</p>
<p>— Опять начинается. — Мы зашли в лифт, и он продолжил: — Нужно ответственнее быть, Ярослав, это твоё будущее. Какая разница. В университете у вас вообще будет огромный процент самообразования. Не только учат, а ты и сам должен учиться.</p>
<p>Мне нечего было ему ответить. Повторяющийся диалог, только разными словами.</p>
<p>Лифт неспешно довёз нас на шестой этаж, мы зашли в квартиру 22. По крайней мере, номер запомнить не сложно, подумалось мне. Дома была мама, работал телевизор, она проверяла, какие каналы ловит антенна. Щелчок. «Погода этой весной ожида…». Щелчок. «И вернёмся к новост…». Щелчок. «И вот мы начинаем с чистого…».</p>
<p>Разуваясь, я споткнулся и невольно выронил коробку со своими вещами из рук. Несколько книг и тетрадей выпали на пол, из них, в свою очередь, вылетели исписанные листы.</p>
<p>— А, вы уже закончили? — послышался приближающийся голос мамы из комнаты.</p>
<p>Вместо ответа ей отец сказал:</p>
<p>— Ярослав, первые шаги в новой квартире и сразу хаос, — он наклонился, чтобы подобрать упавшее, и удивлённо нахмурился. — Ты что, вместо учебников взял эту макулатуру?</p>
<p>— Саша, что такое? — появилась в дверях мама.</p>
<p>Пользуясь моментом, я быстро наклонился, опередив отца, чтобы подобрать разбросанные по прихожей книги и листы.</p>
<p>— Оля, Ярослав решил взять с собой вместо учебников свою макулатуру. Нет, я понимаю, что переезд нам оплатила компания, но Ярослав, видимо, не понимает, что она оплачивает переезд людям, которые умеют работать, а не тем, которые просто умеют читать.</p>
<p>Услышав эту реплику, я ускоренно стал собирать книги и листы. Да уж, жалкая попытка восстановить порядок. Устранить видимый хаос, как сказал бы отец. Испытал чувство вины, но не за то, что взял с собой то, что мне нравилось, а за то, что в очередной раз это приводило к упрёкам.</p>
<p>— Я в комнату, — сказал родителям, когда дособирал листы, стараясь побыстрее уйти от классического сюжета нравоучений.</p>
<p>В своей комнате я поставил на стол последнюю коробку. Достал из неё новую тетрадь, которую купил перед отъездом. Провёл по ней рукой, словно протирая от невидимой пыли переезда. Обычно я писал в тетради небольшие заметки или рассказы. Надеюсь, и здесь будет о чём написать.</p>
<p>Рядом, на полу, в других коробках были упакованы все мои привычные вещи. Удивительно, подумалось мне, вот так 17 лет жизни в итоге фасуются по коробкам и просто меняются декорации. Поэтично, — ответил сам себе.</p>
<p>Принялся разбирать вещи по шкафам и на одной из полок наткнулся на небольшую коробочку, которая явно была не из моих вещей. Видимо, осталась от прошлых жильцов. Аккуратно открыл её и разочарованно выдохнул. Ну, какой-то хлам: старые детали непонятно от чего, выцветшая карточка с поблекшими чернилами, винтики, блок питания с пометкой 24V. Уже разочарованный хотел кинуть в импровизированную мусорку, но моё внимание привлекло что-то ещё, что было в коробке. Аккуратно завёрнутое в бумагу.</p>
<p>Раскрыл её и увидел внутри серебряную фигурку цапли с чернением.</p>
<p>У неё были изящные и плавные линии, очень высокая детализация. В некоторых местах грани отражали свет, добавляя ещё большей загадочности фигурке. Да, не понимаю, почему её оставили.</p>
<p>Сначала мне показалось, что нужно сказать родителям, может, следует связаться с прошлыми жильцами или хозяевами квартиры, вдруг её забыли, но потом я подумал, что раз все крупные вещи вывезли, а эта коробка осталась, значит, её просто не захотели брать.</p>
<p>Ну нет, оставлю себе.</p>
<p>Я взял цаплю и поставил её на подоконник. Мне показалось, что там ей самое подходящее место. Выглянул в окно и увидел уже знакомый мне двор, идентичный панельный дом напротив. Вокруг виднелся такой же стандартный спальный район, дворы, дома, ничего необычного. Но мой взгляд привлекло то, чего раньше я видеть не мог. Между домами виднелась Волга. Несмотря на то, что до неё было не меньше километра или двух, она всё равно казалась очень большой. Я никогда раньше её не видел, но река показалась мне смутно знакомой, я ощутил необъяснимый прилив сил. Иронично: вода и прилив сил. Улыбнулся.</p>
<p>Нужно обязательно к ней сходить.</p>`,
    1: `<p>Разложив большую часть своих вещей, я решил, что сейчас самое время прогуляться до Волги. Всё равно уборка и разбор вещей продолжатся и завтра. Я вышел из своей комнаты и направился к родителям, чтобы отпроситься.</p>
<p>— Ну как же хорошо! — услышал я голос отца из комнаты. — Неужели будет всё нормально. Больше никаких соседей сверху. Ни музыки, ни хаоса с топаньем и вечеринками. Никакого нарушения порядка.</p>
<p>— Да, — ответила ему мама. — Риелтор так и сказала, что квартира над нами опечатана. Уже очень давно. Наследники то ли уехали, то ли ещё что-то, поэтому в ней точно никто не живёт и вряд ли будет.</p>
<p>— Отличные новости, — сказал отец и, увидев меня, добавил. — А, Ярослав, ты разобрался в комнате?</p>
<p>— Да, почти, пап. Можно я немного передохну и прогуляюсь по городу? Завтра ещё целый день будем приводить квартиру в порядок, — поспешил добавить я.</p>
<p>— Саша, пусть Ярослав прогуляется, новый город всё же, интересно, — поддержала меня мама.</p>
<p>— Ну, хорошо, только не допоздна. Мать завтра пойдёт в школу, мы с ними связывались, отнесёт документы. Ты завтра здесь за главного будешь, чтобы убраться и разобрать вещи. Я уже завтра на работу.</p>
<p>Чтобы не упустить момент, я быстро накинул вещи и вышел в подъезд, оставив родителей наедине. Они уже продолжили обсуждать планы на новом месте.</p>`,
    2: `<p>Воздух казался мне другим.</p>
<p>Нет, дело вряд ли в чём-то сверхъестественном. Уверен, что всё это было из-за Волги. Большая река, которая протекала вдоль всего города, определённо влияла на влажность и на сам запах воздуха в городе.</p>
<p>Я шёл по центру города немного грустным. Позади остался привычный мне мир, мои знакомые, моя школа, мой дом. Отец говорил, что всё это здорово, но сентиментальная чепуха не должна влиять на жизнь. Впереди меня ждёт поступление и обучение в вузе. Он очень сильно хотел, чтобы я продолжил его дело. Быть инженером — гордо и престижно. Инженеры зарабатывают. Инженеры делают. Благодаря людям дела вращается мир. Дайте мне точку опоры и… И множество-множество подобных карикатурных и плоских мантр.</p>
<p>— Завод ждёт тебя, инженер, — с досадой сказал я и ударил по пустой банке из-под газировки, что валялась под ногами. Она со звоном полетела вниз по гранитным ступенькам, и я понял, что уже стою на центральной набережной. Поднял глаза и увидел Волгу перед собой.</p>
<p>Её мощь и тёмные воды завораживали. Я почувствовал резкий и тяжёлый запах: здесь было всё, и вода, и сырость, и ил, и песок, и необъяснимо что-то ещё. Что-то, что я не мог назвать, перебирая бессознательно слова. Что-то древнее, первородное. Чувствовал, как оно движется. Нет, не течение, что-то глубже, что-то сильнее.</p>
<p>Этот вид поглотил всё: ветер, звуки города, машины, людей. Всё словно слилось воедино. Я почувствовал необъяснимое желание идти к ней. Но не чтобы утонуть, нет. Словно мне хотелось установить с ней связь. Или раствориться в этой титанической силе, стать частью чего-то вечного.</p>
<p>Я чувствовал, как колотится моё сердце, но это был не страх, а всепоглощающее любопытство. Словно я слышал зов. Меня звали.</p>
<p>И я хотел туда прийти.</p>`,
    3: `<p>Ветер резко подул с реки, ударив обжигающим холодом по лицу.</p>
<p>Этот порыв вырвал меня из транса. Непроизвольно растёр ладонями лицо и понял, что стою уже на берегу, возле тёмной воды. Шаг, который я хотел сделать по направлению к Волге, был не шагом по ступенькам. Я понял, что занёс ногу уже над самой водой.</p>
<p>Медленно поставил ногу обратно на землю. Сердце вновь застучало, но в этот раз полностью от страха. Я обернулся и увидел, что за эти мгновения преодолел огромные лестницы набережной. Что это было? Я же только секунду назад был наверху, когда увидел Волгу.</p>
<p>Поспешно, почти бегом направился обратно. Теперь подъём по лестницам набережной занял некоторое время. И это восхождение ощущалось как переход из чего-то свежего и родного в нечто бездушное, сухое, тесное. Воздух словно становился суше и потерял свой вкус. Я поднимался по ступенькам, не останавливаясь, пока у меня не появилась одышка. Но ощущение зова не прекращалось, этот магнетизм реки словно шёл уже откуда-то изнутри</p>
<p>Остановился наверху лестницы, откуда впервые увидел Волгу. И в этот момент заметил листок бумаги, приклеенный на одной из колонн пропилеи.</p>
<p>ПРОПАЛ БЕЗ ВЕСТИ — прочёл я.</p>
<p>Чёрно-белая фотография, парень, лет 15–16. Обычное лицо и чуть неуверенная улыбка. Я прочёл имя, которое тут же забыл. А вот лицо почему-то мне запомнилось. Видел его ясно и чётко. Мне казалось, что я его откуда-то знаю. Или я где-то его видел.</p>
<p>Бумага вздулась от влажного воздуха возле реки, делая лицо чуть размытым, почти прозрачным. Уголок был оторван, будто кто-то пытался сорвать этот листок, но оторвал лишь клочок.</p>
<p>Я пошёл дальше. Стало холодно. Да и вряд ли дело было только в погоде. Куда можно пропасть в этом городе? Сбежать? Или исчезнуть. И не в реке ли, как только что чуть не исчез я?</p>
<p>Небо, до этого яркое и красное от заката, начало стремительно темнеть. Появились небольшие снежинки.</p>`,
    4: `<p>Я шёл по спальному району, уже недалеко от своего нового дома.</p>
<p>Навстречу мне шли потоком прохожие, начинавшие возвращаться с работы домой. Мигали разноцветные вывески немногочисленных продуктовых магазинов. Я размышлял о Волге, об исчезнувшем подростке. Также думал про переезд, новую школу, новый класс. Что ждёт меня там? Найду ли я с кем-то общий язык? Будет ли интересно?</p>
<p>Снег усилился, и я пошёл быстрее, подгоняемый холодным ветром, ориентируясь по ставшим смутными силуэтам фонарей.</p>
<p>И тогда случилось нечто по-настоящему жуткое.</p>
<p>Фонари стали мерцать. Нет, не так, как они мигают при плохом контакте, а пульсировать в такт моему сердцебиению. Вспышка. Погасли. Вспышка. Погасли. Мне стало страшно, и фонари, синхронно чувствующие мой пульс, ускорились. Снег всё усиливался и усиливался, превращаясь в настоящую метель. Из окон домов то тут, то там мерцали телевизоры, словно их поставили на подоконник. Это жуткое зрелище из голубоватых экранов помех, мерцающих в унисон, превращалось в демонический стробоскоп, сбивающий с толку.</p>
<p>Я ускорился, почти перейдя на бег. В моей голове крутилась одна и та же мысль. Это кто-то видит, кроме меня?</p>
<p>И в этот момент я вдруг осознал, что никого и ничего больше нет. Нет домов, которые до этого были вокруг меня, нет людей. Ни одного прохожего на дороге, где ещё минуту назад они шли потоком. Только пустота и снег вокруг. Исчезли даже звуки, я словно оказался в вакууме.</p>
<p>— Кто здесь? — закричал я.</p>
<p>И мой голос звучал несколько искажённо. Я повторил ещё раз и ещё громче, в отчаянной надежде на чей-то отклик, на то, что кто-то ответит мне и что я не остался в этом ужасе один. Но мне ответило лишь что-то, отдалённо напоминающее эхо.</p>
<p>— Кто здесь, кто здесь.</p>
<p>Запоздало и дважды.</p>
<p>Появился звук помех, будто настраивали радио. И в этот момент я не мог понять, идёт ли этот звук извне или же он внутри меня.</p>
<p>— Никчёмный, — услышал я шёпот вдали от себя, — Хаос… Жалкий…</p>
<p>Резко обернулся и увидел тёмный силуэт позади. Он был недалеко, но и не близко, метрах в пятидесяти от меня. Я не мог понять, как мне удаётся видеть его через такую пелену снега, что так и продолжала идти, словно стеной.</p>
<p>Больше не сдерживаясь, я в ужасе побежал, то и дело спотыкаясь о неровности дороги, которые не были видны из-за высоты выпавшего за несколько минут снега. И в какой-то момент снег вокруг начал раскалываться. Как по разбитому льду, паутиной стали появляться трещины. Маленькие, но быстро растущие. Чёрные. Пахнущие тиной и илом. И от них начинал подниматься туман, похожий на ледяной пар.</p>
<p>Я бежал и боялся повернуться, чтобы не увидеть тот чёрный силуэт возле себя. Бежал, пока чёрная трещина не появилась под моими ногами, и тогда я отчаянно прыгнул в попытке не провалиться в неё. И упал.</p>
<p>Лёжа с закрытыми глазами, я боялся пошевелиться.</p>
<p>Это конец, — подумалось мне.</p>
<p>Но ничего не происходило. Открыл глаза. Никого. Осторожно поднялся. Огляделся вокруг. Нет, ни чёрного силуэта, ни трещин.</p>
<p>Привычная реальность. Мимо спешили люди, просигналил проезжающий автомобиль. Всё было как до метели. Но снега действительно было больше.</p>
<p>Я пошёл домой.</p>`,
    5: `<p>Дома пахло едой, мама за время моего отсутствия уже успела приготовить ужин. Я неуклюже разулся, споткнулся и зашёл в ванную, чтобы вымыть руки.</p>
<p>— Ярослав, скоро ужин, — донёсся мамин голос с кухни, перекрывая звук льющейся воды из крана. Она услышала, что я вернулся.</p>
<p>— Мам, я пока не хочу, — крикнул я.</p>
<p>Есть мне абсолютно не хотелось. Меня мутило, и всё вокруг словно плыло. Я бесконечно прокручивал вновь и вновь моменты метели, исчезновения всего, жуткий стробоскоп и чёрный силуэт. Это видение прервал голос отца.</p>
<p>— Что значит не хочу, Ярослав? У нас семейный ужин на новом месте. Никаких не хочу. Раздевайся, и мы ждём тебя.</p>
<p>— Хорошо, пап, — механически ответил я, выключая воду.</p>
<p>Зашёл в свою комнату и, даже не включив свет, начал переодеваться в домашнюю одежду, которую увидел в свете, падающем из окна. Руки не слушались меня, я не мог попасть в рукава футболки, бесконечно возвращаясь к своему видению. Что это было? — крутился огромным транспарантом вопрос в моей голове. Подошёл к окну, посмотрел на Волгу и вновь почувствовал тот исходящий магнетизм. Сейчас он не был таким сильным, как возле неё, но я всё равно чувствовал, будто это ощущение было внутри меня.</p>
<p>Случайно задел локтем статуэтку цапли. Она упала.</p>
<p>Наклонился, чтобы поднять её, и увидел возле пола небольшую трещину в стене. Ни за что не заметил бы её в темноте, но она словно светилась изнутри тусклым голубым светом. Рефлекторно провёл по ней пальцами. Она никак не выделялась на ощупь, словно стена была гладкой. Меня охватило странное чувство, словно я понимаю, почему она здесь, но не могу себе объяснить.</p>
<p>— Чертовщина. Я схожу с ума. Нужно отдохнуть, это переезд, — проговорил я, как мантру.</p>
<p>Протёр глаза, но трещина не исчезла. </p>`,
    6: `<p>Я прошёл на кухню, сел за стол. Отец настраивал телевизор на кухне, мама в этот момент накладывала еду.</p>
<p>— Вы знаете, я тут на набережной листовку видел, — сбивчиво сказал я. — И не только. Ещё метель. Страшную. Фонари. Тут парень пропал.</p>
<p>Попытался завести разговор, чтобы как-то успокоиться.</p>
<p>— Не накручивай себя, Ярослав, — отстранённо ответил отец и тут же раздражённо добавил. — Вот вам современная техника!</p>
<p>Телевизор зашипел. Экран вздрогнул, изображение раздвоилось, затем вовсе исчезло и поползли помехи.</p>
<p>— Что такое, Саша? — ответила ему мама.</p>
<p>— Да что, Оля, не работает ни черта. Вот делали же люди нормально, а теперь одни бездари везде. Опять эта китайская халтура. То, что пятьдесят лет назад делали, — до сих пор работает, а что пять лет назад сделали, — всё, нужно менять, покупайте новое. Капитализм.</p>
<p>— А причём тут капитализм? — машинально сказал я.</p>
<p>Мать уронила вилку и быстро её подняла.</p>
<p>— А я тебе скажу. Потому что сынки богатеньких покупают себе корочки и идут работать туда, куда раньше их бы на пушечный выстрел не подпустили. Делать не умеют, одна цель — пусть сломается и купят новое. А китайцы и еже с ними, так вообще только быстро ломающийся пластик и штампуют. Какая разница! Ведь всё равно — купят, купят, купят. Одна цель.</p>
<p>— Ну ладно вам, — сказала примиряюще мама, — давайте уже ужинать, бог с ним, с телевизором.</p>
<p>— Да всё, вроде настроил, — сказал отец, прихлопнув по телевизору.</p>
<p>Что-то щёлкнуло внутри. Телевизор будто выдохнул, и картинка, вернувшись, встала на место. Ведущий новостей сидел за столом, серьёзный, с голубоватым оттенком кожи от экрана.</p>
<p>— ...продолжаются поиски пятнадцатилетнего подростка, — говорил он.</p>
<p>Я вздрогнул, потому что с экрана телевизора в этот момент на меня смотрел тот парень, которого я видел на листовке. Лицо было его.</p>
<p>— Ну вот, — отмахнулся отец, — смотрите, что теперь по телевизору показывают. Наверняка сбежал, чтобы в школу не ходить. У друзей ночует и в компьютерные клубы ходит. Вернётся, когда карманные деньги кончатся.</p>
<p>Мать смотрела на экран.</p>
<p>— Бедные родители, — грустно проговорила она. — Но может, правда что-то случилось?</p>
<p>— Ой, Оля, я тебе говорю. Причём, вот ирония-то, а! Полежаев. Вот раньше был Полежаев, инженер, в честь него, как раз, и Полежаевскую назвали. А теперь смотрите….</p>
<p>Мать замолчала. Я знал, что она не станет спорить. Она никогда не спорила.</p>
<p>Я сидел между ними. Слева методично жующий отец, справа молчащая мать. Телевизор продолжил о погоде, курсе валют, о чём-то ещё. В этот момент я ощутил, как стена вокруг меня поднимается. Невидимая, но прочная.</p>
<p>Оставшийся ужин мы ели молча.</p>`,
    7: `<p>Ночью долго не мог уснуть, постоянно ворочаясь и словно ощущая в квартире чьё-то чужое присутствие. Но усталость неизбежно взяла верх над телом, после чего я провалился в достаточно тревожный сон.</p>
<p>Мне снилось, что я нахожусь на берегу Волги, но не на набережной, а на крутом, обрывистом берегу. За Волгой я вижу какой-то сияющий город и очень хочу туда попасть. Но не знаю, как преодолеть реку. И берег очень извилистый, с оврагами, крайне опасный.</p>
<p>Я поворачиваюсь назад и вижу тень, силуэт, который видел в метели. Силуэт механическим голосом произнёс:</p>
<p>— Построй мост, не витай в облаках.</p>
<p>Это было очень логично, отметил я, но почувствовал тоску и расстройство, мне казалось, что это неправильно. Силуэт стоял вдалеке, но я знал, что нужно что-то делать. Не хочу, чтобы он оказался рядом.</p>
<p>Пока я колебался, перебирая в голове идеи, вдруг со дна, прямо из середины реки всплыла огромная цапля, та самая, что была у меня статуэткой на подоконнике. Она была гигантской, наверное, размером с шестнадцатиэтажку. Расправив крылья, цапля обратилась ко мне. Она не говорила, но я понимал её послание — слова словно возникали внутри.</p>
<p>— Река не терпит мостов. Река хочет, чтобы по ней плыли. Ты должен спуститься и найти свою лодку.</p>
<p>После этого я проснулся с ощущением сильной тревоги, но и с каким-то непонятным мне проблеском надежды. Оглядел комнату. Цапля действительно была на подоконнике.</p>
<p>И её размер со вчера не изменился.</p>`,
    8: `<p>Я вышел из своей комнаты с ощущением, будто и не спал вовсе. На кухне были родители. Отец, бодрый и выспавшийся, собирался на работу.</p>
<p>— Ну что, главный по уборке, план действий подготовил? — спросил он, допивая кофе. — Вещи в коробках, не везде ещё убрано, сегодня твой день.</p>
<p>— Да, конечно, пап, — равнодушно ответил я.</p>
<p>— Оля, ты сходишь в школу? — он повернулся к маме.</p>
<p>— Конечно, как договорились, думаю, проблем не будет, — ответила она, собирая отцу пакет с едой на работу.</p>
<p>Я не понимал, что именно, но меня настораживал тот уют, вернее, то упорство, с которым мама старалась создать уют. Вроде никаких особых действий не было, но мне казалось, что что-то не так. Неестественно.</p>
<p>Сначала отец ушёл на работу. Чуть позже мама пошла отдавать документы в школу. Я остался один в квартире и механически принялся за уборку, план которой мысленно составил уже на ходу. Руки сами протирали стеллажи от пыли, разбирали коробки, развешивали одежду по вешалкам и прочее. А вот мысли путались, возвращаясь к одному и тому же. Волга. Метель. Силуэт. Пропавший…</p>
<p>Подошёл к месту, где упала статуэтка цапли. Трещина в стене была на месте... Я провёл по ней пальцем — всё так же гладко. Река хочет, чтобы по ней плыли. Что это значит? Найти лодку? Это метафора.</p>
<p>Должно быть, метафора.</p>`,
    9: `<p>Мама вернулась из школы. Я услышал, как ключ поворачивается в замке.</p>
<p>— Ну всё, Ярослав, — сказала она, разуваясь в прихожей. — Завтра к восьми тебя ждут в школе. Директор очень милая женщина. Говорит, класс хороший, ребята собранные, помогут влиться. Единственное, в физмате, как просил папа, мест нет. Но ты же у нас умный мальчик, ты и так, я не сомневаюсь, справишься.</p>
<p>Она говорила это с такой наивной, светлой верой, что мне даже стало неловко за свои мысли.</p>
<p>— Спасибо, мам, — выдавил я.</p>
<p>— Что-то ты бледный. Не выспался?</p>
<p>— Да, немного, — соврал я. — Новая кровать, непривычно.</p>
<p>— Приснилось что-то?</p>
<p>— Да не, просто устал. Переезд.</p>
<p>Она понимающе кивнула. Вечером отец вернулся с работы усталый, но вместе с тем достаточно радостный. Он рассказывал о новом проекте, о коллегах, о руководителе филиала. Казалось, ничего не может омрачить его настроение. Кроме одного. Мать рассказала про отсутствие мест в классе физмата.</p>
<p>Отец очень долго возмущался, кричал, вспоминал вчерашний разговор про капитализм.</p>
<p>— Всё через деньги, — кричал он. — Они сами себе роют могилу. Как в стране будут инженеры, если их не берут на учёбу? Наверняка хотели взятку…</p>
<p>И многое другое. Я постарался как можно быстрее доесть и ушёл.</p>
<p>Отец продолжил свои тирады. </p>`,
    10: `<p>Долго ворочался и не мог уснуть. А затем, когда начал проваливаться в сон, появился он. Методичный и нарастающий звук. Начал работать перфоратор.</p>
<p>Словно пытаясь зарыться, я накрыл свою голову подушкой. Но звук не прекращался. Закрыл уши. Звук не исчез, а напротив, нарастал, словно пульсируя внутри головы. Что это? Галлюцинация? Почему никто ничего не делает? Этот звук уже должен был разбудить если не дом, то весь подъезд. Я встал с кровати, прислушался и для точности приложил ладонь к холодной стене. Звук и вибрация явно шли из квартиры сверху.</p>
<p>Не понимая, что делать, немного постоял, но звук и не думал умолкать. Не выдержав гула, направился в родительскую спальню. Родители спали, как ни в чём не бывало. Я потрогал отца за плечо и сказал:</p>
<p>— Пап, ты слышишь?</p>
<p>Он недовольно ответил в полудрёме:</p>
<p>— А, Ярослав, что?</p>
<p>Но стоило ему ответить, как звук исчез.</p>
<p>— Перфоратор. Сейчас кто-то сверлил перфоратором.</p>
<p>— Ярослав, тебе приснилось. Никто не сверлит. Спи, — сонно ответил он и перевернулся на другой бок.</p>
<p>Тишина. Вокруг была гробовая тишина. Ничего не понимая, я вернулся в свою комнату и лёг в кровать. Никаких звуков больше не было.</p>
<p>Я заснул.</p>`,
    11: `<p>Утром заверещал будильник.</p>
<p>Я нашёл его на ощупь, выключил и сел на кровати. Открыл глаза, проступили очертания комнаты в сером свете из окна. Ощущение — что и не спал вовсе. Прислушался. Нет, перфоратор молчит. Может, и вправду показалось.</p>
<p>Вновь закрыл глаза, собираясь с мыслями. Трещина. Точно. Вновь открыл глаза, посмотрел в сторону окна, вниз. Тусклое голубоватое свечение стало более блёклым, но сама линия никуда не делась — тонкая, идущая вдоль стены. Как будто у неё была цель, к которой она стремилась.</p>
<p>Я отвёл взгляд.</p>
<p>Встал. Механически, как на автопилоте, прошёл в ванную. Умылся ледяной водой, надеясь, что это вернёт меня в реальность.</p>
<p>Под глазами в зеркале залегли тени, которых ещё вчера не было. Я смотрел на себя в отражение и впервые не узнавал. Нет, не внешность, с ней было всё в порядке. Взгляд. Что-то изменилось внутри меня. Будто за ночь что-то сдвинулось.</p>
<p>Вернулся в свою комнату, оделся.</p>
<p>Из кухни пахло кофе. Мама собирала отцу еду на работу. Он сидел за столом, просматривая какие-то распечатки с таблицами, и быстро пил кофе. Его лицо было сосредоточенным, губы чуть шевелились, когда он пробегал глазами по цифрам.</p>
<p>— Доброе утро, — сказал я.</p>
<p>— Доброе, — отозвался он, не поднимая глаз. — Первый день в новой школе. Постарайся произвести хорошее впечатление. И не опаздывай.</p>
<p>Мама подошла, поправила воротник моей рубашки и улыбнулась.</p>
<p>— Всё будет хорошо, Ярослав. Ты же у нас умный. Найдёшь друзей, вольёшься. Школа хорошая, гимназия! Рядом совсем.</p>
<p>Я кивнул. Признаться, но новые друзья — это не то, что сейчас меня волновало. Но что я им скажу? Что думаю про метель, чёрный силуэт и телевизоры в окнах? Или про перфоратор, который, неизвестно, был или нет?</p>
<p>Позавтракал через силу. Мама что-то рассказывала о вчерашнем визите в школу, о том, какая там столовая, какой спортзал, каких видела учителей. Я слышал, но не слушал, фоново кивая в нужных местах, но мысли всё время возвращались к одному и тому же. Квартира сверху. Опечатанная. И звук, который разбудил меня ночью.</p>
<p>Когда я вышел в прихожую, родители ещё оставались на кухне. Отец уже переключился на утренние новости по телевизору. Мама гремела посудой. Я накинул куртку, повесил рюкзак на плечо и открыл входную дверь. Вышел на лестничную клетку.</p>
<p>Подошёл к лифту, нажал кнопку вызова. Где-то в шахте загудел механизм. Кабина пришла в движение. Стоял и ждал, смотрел на двери, которые вот-вот должны были открыться.</p>
<p>Вдруг пришла мысль. А чего я не проверю эту квартиру? Если там сверлят, то, может, просто сказать, что это безумие — сверлить по ночам? Всего минута. Что я потеряю?</p>
<p>Осторожно поднявшись по ступенькам, словно они были заколдованы и могли исчезнуть в любой момент, я увидел на седьмом этаже дверь квартиры с номером 26, которая была аккурат над нашей. Услышал, как на моём этаже открылся лифт.</p>
<p>Дверь была пыльная и старая, с массивным амбарным замком, повешенным в специально приваренные для этого петли. Следов человеческого пребывания не было. Я огляделся. Остальные квартиры на этаже, а их было три, выглядели как обычные двери в обычные квартиры. Где живут обычные люди, которые не слышат необычный перфоратор? Не знаю.</p>
<p>Я постоял ещё немного на этаже, словно к чему-то прислушиваясь, и попеременно вглядываясь в каждую из дверей. Ничего необычного, ничего, что могло бы насторожить. Это такой же этаж, как и наш, только одна из дверей давно закрыта. Как и сказала тогда мать, то ли наследники уехали, то ли ещё что-то, я уже не помню.</p>
<p>Откуда тогда идёт звук? Откуда звучит этот чёртов перфоратор?</p>
<p>И опять, неужели квартиры рядом не слышали? Или слышали, но привыкли? А может, звук действительно существовал только в моей голове? Галлюцинация. Нервный срыв. Акклиматизация. Стресс после переезда. В конце концов, я читал где-то, что мозг может выдавать странные фокусы в период адаптации.</p>
<p>— Я на седьмом этаже, — прошептал я сам себе. — Это как шестой, но на один повыше.</p>
<p>От комичности и перенапряжения я рассмеялся.</p>
<p>Выдохнув, спустился на свой этаж и нажал на вызов лифта. Двери быстро раскрылись. Я поехал вниз.</p>`,
    12: `<p>Улица встретила туманом.</p>
<p>Он был плотный, почти осязаемый. Сквозь него проступали силуэты девятиэтажек, размытые и искажённые, будто смотришь на них сквозь грязное стекло от бутылки.</p>
<p>Всё вокруг стало глухим или приглушённым. Даже мои собственные шаги по асфальту казались чужими, словно кто-то другой шёл совсем рядом, невидимый, но повторяющий мой ритм.</p>
<p>Я шёл и повторял в голове инструкцию от матери. Выйдешь из подъезда, двор по диагонали, выйдешь к дороге, перейдёшь. Потом прямо, никуда не сворачивая. Дойдёшь до другой дороги, перейдёшь и там тоже двор по диагонали, влево. Минут десять, не заблудишься. Всё просто.</p>
<p>Просто. Всё просто. Да, естественно. Было бы всё очень просто, если мир вёл себя так, как должен.</p>
<p>Прошёл двор, перешёл дорогу. Теперь прямо, не сворачивая. Улица была пустынной. Лишь изредка появлялись другие прохожие, материализуясь из тумана, а затем также внезапно в нём исчезая.</p>
<p>Вторая дорога. Теперь двор по диагонали налево. Туман начал редеть. Сначала очертания деревьев, потом столбы, окна домов. И вот я уже у школьного забора. Вот калитка. Остановился.</p>
<p>Типовая панельная коробка, на фасаде которой красовалось: Гимназия — гордость Волгограда! Ну, не физмат, так гимназия.</p>
<p>Мимо меня проходили школьники, классы помладше заходили с родителями, а я всё никак не мог сделать шаг через порог калитки. Да уж, не каждый день переезжаешь.</p>
<p>Моё волнение прервал чей-то взгляд, пристальный, будто физически ощутимый. Я повернулся направо, пытаясь отыскать источник.</p>
<p>Возле забора стоял мой сверстник, в чёрной кожаной куртке, под ней была толстовка с капюшоном, на которой ярким цветом выделялась эмблема рок-группы, джинсы и высокие ботинки с металлическим носом.</p>
<p>Гриндеры, — машинально подметил я. Всё время хотел их купить себе, но родители были непоколебимы. Отец говорил про маргиналов, мать спрашивала, хочу ли я быть клоуном, и, может, мне нужно в цирк идти работать.</p>
<p>Мой визави курил и смотрел на меня с любопытством. Мне стало неловко, я отвёл взгляд и быстро направился к школе. Ну, зато нерешительность перед школой быстро прошла.</p>
<p>Уже у самых дверей я не выдержал и снова обернулся. Парень не двинулся с места. Он всё так же стоял у забора, курил и смотрел мне вслед.</p>
<p>Я зашёл в школу, оставил верхнюю одежду в раздевалке и отправился к кабинету, следуя дополнительной инструкции матери. Там должна была ждать мой новый классный руководитель. Она встретила меня у входа в класс.</p>
<p>Классная руководительница оказалась женщиной лет сорока с усталым, но добрым лицом. У неё были мягкие морщинки в уголках глаз и приятный, обволакивающий голос. Она поприветствовала меня так, словно уже давно ждала.</p>
<p>— Ярослав? Привет! Я Ольга Васильевна. Мы тебя ждали. Документы твои уже у директора, всё в порядке. Как прошёл переезд? Обживаетесь?</p>
<p>— Да, потихоньку, — ответил я, стараясь, чтобы голос звучал уверенно.</p>
<p>— Ну и славно. Вот что, урок у нас через пятнадцать минут начнётся, давай-ка сходим в библиотеку. Тебе ведь учебники получить надо.</p>
<p>Мы прошли в другое крыло и оказались в школьной библиотеке.</p>
<p>— Надежда Васильевна, вот наш новенький, Ярослав, 11 Б. Выдайте ему, пожалуйста, учебники, которые мы подготовили.</p>
<p>— Конечно, — из-за стола поднялась пожилая женщина. Её движения были плавными, достаточно грациозными. Она взглянула на меня не с любопытством, а словно увидев книгу, которую давно хотела прочесть. — Бери пока часть, — сказала она, подавая мне несколько учебников. Голос у неё успокаивал и словно обволакивал, каждое слово звучало значимо. — Не тащи всё сразу.</p>
<p>Я взял учебники. Они пахли пылью и временем. Некоторым было явно много лет — обложки потёртые, страницы пожелтевшие, кое-где виднелись карандашные пометки. Я уже хотел поблагодарить и уйти, но Надежда Васильевна вдруг спросила:</p>
<p>— Волгу нашу уже видел?</p>
<p>Я вздрогнул. Вопрос прозвучал буднично, но слишком уж точно попал в цель.</p>
<p>— Да, — ответил я. — Вчера.</p>
<p>Библиотекарь кивнула с таким видом, словно получила подтверждение какой-то своей догадке.</p>
<p>— Река древняя... Много кого видела. — Она помолчала, поправила очки, и её взгляд стал совсем уже пронзительным.</p>
<p>Я не нашёлся что ответить. Эти слова звучали странно, почти неуместно, но в то же время у меня было чувство, что за ними стоит что-то важное. Что она не просто так их произнесла.</p>
<p>— Вот, держи ещё, — она протянула мне открытку.</p>
<p>Я взял её. На глянцевой поверхности была изображена река. Художник изобразил её в стиле старой гравюры. Внизу подпись Царица.</p>
<p>— Царица? — переспросил я. — Я думал, город на Волге стоит.</p>
<p>— И на Волге, и на Царице, — ответила Надежда Васильевна. — Царица в Волгу впадает. Раньше город Царицыном звался. Теперь Волгоград.</p>
<p>— Спасибо, — выдавил я и аккуратно убрал открытку в учебник.</p>
<p>Ольга Васильевна, всё это время терпеливо ждавшая у двери, кашлянула.</p>
<p>— Ну что, идём в класс? Ребята скоро соберутся, я тебя представлю.</p>
<p>Мы попрощались с библиотекарем и направились в класс.</p>`,
    13: `<p>Ольга Васильевна зашла со мной в класс. Первым уроком была физика.</p>
<p>— Игорь Петрович, — обратилась она к учителю, — я прошу прощения. Класс, всем минуту внимания. К нам сегодня присоединяется новый ученик, его зовут Ярослав. Пожалуйста, помогите Ярославу освоиться в новом городе, он приехал к нам из Москвы. Давайте покажем, что волгоградцы — очень воспитанные и прилежные ученики. Да? Вы согласны?</p>
<p>На меня с разной степенью любопытства и безразличия уставилось двадцать пять человек. Негромко по классу пролетело: — Да, конечно.</p>
<p>— Ярослав, присаживайся на свободные места, если что, обращайся. Ты помнишь, где меня найти. Хорошего дня, — в напутствие добавила Ольга Васильевна.</p>
<p>Я испытал невероятное волнение, но внутренне знал, что обязательно должен что-то сказать. Через страх я попытался улыбнуться.</p>
<p>— Очень рад присоединиться к вам. Я Ярослав, — выдавил из себя я.</p>
<p>Голос прозвучал глуше, чем мне хотелось. Слова вышли скомканными, будто я подавился ими на полпути. По классу пробежал лёгкий шелест — кто-то кивнул, кто-то шепнул соседу, кто-то просто отвёл взгляд, потеряв ко мне интерес. Я поспешил пройти на свободное место за последней партой, пока пауза не затянулась до неприличия.</p>
<p>Расположившись, достал учебник, открыл его на случайной странице и под него положил свою новую тетрадь, но не школьную, а для заметок. Учитель физики, пожилой мужчина, продолжил урок.</p>
<p>— У нас сегодня новая тема. Это электромагнитные колебания. И ключ к пониманию этой главы лежит через явление, которое вы уже немного знаете с прошлых классов. Через резонанс. Кто мне напомнит, что такое резонанс, с примером?</p>
<p>Учитель сделал паузу, ожидая ответа. Я аккуратно достал тетрадь из-под учебника и начал водить ручкой по листам, выводя слова. Не дождавшись добровольцев, учитель продолжил.</p>
<p>— С точки зрения физики, резонанс — это резкое возрастание амплитуды колебаний системы, когда частота внешней, вынуждающей силы совпадает с собственной частотой колебаний этой системы.</p>
<p>Я на мгновение поднял глаза и увидел её… Она сидела на второй парте, через одну от меня.</p>
<p>— Проще говоря, мир постоянно толкает нас с разной частотой.</p>
<p>Не знаю, как описать то, что я почувствовал. Это не было ударом молнии, о котором пишут в книгах. Ни вспышкой, ни головокружением. Нечто иное. Тихое, но глубокое, почти забытое. Словно я впервые оказался там, где должен был быть.</p>
<p>Она не была похожа на других. Дело даже не во внешности, хоть и внешность была необычной. Русые волнистые волосы, мягко касающиеся плеч, и изящные черты лица. Главное было не в этом. В её позе скользила какая-то гармония. Я видел её лицо в полупрофиль и чувствовал какое-то непреодолимое желание заглянуть ей в глаза, словно я найду там то, что мне нужно. Она что-то неспешно выводила в тетради ручкой. Каждое её движение было плавным и осмысленным. Словно она знала нечто такое, чего не знали все остальные в этом классе. И не спешила этим делиться. Нужно обязательно придумать повод, как с ней заговорить. Что-то спросить. Как её зовут. Нет, это слишком плоско. Что она рисует. Или что пишет в тетради, да, точно…</p>
<p>— Но мы откликаемся по-настоящему сильно только тогда, когда этот толчок попадает в наш внутренний ритм.</p>
<p>Она неожиданно повернулась ко мне, и наш взгляд встретился. Она улыбнулась, но не так, как улыбаются ради приличия. В этой улыбке было что-то иное, словно мы всегда были знакомы. Я почувствовал что-то давно забытое. Она как будто принимала меня. У меня промелькнуло чувство, будто я её знаю. Причём мы знакомы всю жизнь.</p>
<p>Почувствовал, как кровь приливает к лицу, наверняка стал пунцовым. Поспешно отвернувшись, понял, что всё равно улыбаюсь. До конца урока я не решался посмотреть в её сторону.</p>`,
    14: `<p>Прозвенел звонок.</p>
<p>Резкий и пронзительный, он разорвал тишину в классе и одновременно разорвал то странное оцепенение, в котором я пребывал последние минуты урока. Все вокруг зашевелились, зашуршали рюкзаки, загремели стулья. Я машинально закрыл тетрадь, в которой так ничего толком и не записал, и уже собирался встать. Мне необходимо было подойти к ней, увидеть её, заговорить. Пока она не ушла.</p>
<p>Остаток урока я продумывал разговор, прокручивал в голове разные варианты, отметая глупые, разбирая те, что казались естественными. Важно было только подойти.</p>
<p>Но прежде чем я успел это сделать, пространство перед моей партой заслонила чья-то фигура. Я поднял взгляд.</p>
<p>Передо мной стоял парень в безупречно отглаженном костюме. Не в школьной форме, не в пиджаке из тех, что носят старшеклассники на олимпиады, а именно в костюме — дорогом, сидящем по фигуре так, словно его шили на заказ. Светлая рубашка, никаких складок. Галстук, затянутый узлом. Этот костюм был неуместен здесь, в обычном классе, и парень это знал. Именно поэтому он его носил. Чтобы подчеркнуть, что он другой.</p>
<p>Ну, круто, сын богатых из американских фильмов появился. Сейчас ещё где-то черлидерши будут, подумалось мне.</p>
<p>— Москвич, как поживаешь?</p>
<p>Голос у него был соответствующий. Уверенный, громкий ровно настолько, чтобы его услышали все, кто остался в классе. Не вопрос, а скорее заявление о себе. Я попытался выглянуть из-за его плеча, бросить взгляд туда, где ещё минуту назад сидела она. Вторая парта. Но стул был пуст. Девушка с русыми волнистыми волосами уже собрала сумку и, смеясь с кем-то из подруг, выскользнула в коридор. Я увидел только отдаляющийся силуэт и край рукава её кофты, мелькнувший в дверном проёме. Не успел.</p>
<p>— А, привет, — ответил я, стараясь скрыть разочарование.</p>
<p>— Я Анатолий. Толя Фёдоров.</p>
<p>Он глянул на свой телефон, видимо, ему кто-то позвонил, но тут же убрал его и протянул мне руку. Рукопожатие у него было крепким, но каким-то неестественным, словно он тренировал его перед зеркалом.</p>
<p>— Слышал, твой отец в наш проектный институт перевёлся. Мой батя там же работает, но повыше, рулит филиалом, — продолжил он и сел за соседнюю парту.</p>
<p>— Приятно. Ярослав, — выдавил я из себя, стараясь, чтобы голос звучал нейтрально.</p>
<p>— Места у нас тут не простые. Ну, конечно, не Новокузнецк и не Химмаш, зря пугать не буду. Но могут быть проблемки, — понизив голос, протянул он, сгущая краски, но тут же, чтобы приободрить, быстро добавил. — Но если будешь со мной вращаться, вопросы отпадут!</p>
<p>Рука сама потянулась к тетради, которая всё ещё лежала на парте. Я незаметно, как мне казалось, задвинул её под учебник. Не хотелось, чтобы кто-то спрашивал, что я там пишу. Тем более — он.</p>
<p>— Слушай, а почему ты не в физмате? — внезапно мелькнула мысль в голове. — У тебя же отец рулит филиалом, инженер.</p>
<p>— Пф, — с ухмылкой выдохнул он. — Какая разница? Это же лажа, всё это обучение в школе. Тут как для лохов учат. Репетиторы, допкурсы, всё остальное. Вот, где знания. В школе это не купишь, а так — не дадут.</p>
<p>И он поправил руками укладку волос.</p>
<p>В первое мгновение я не придал этому значения, а потом задумался. Его идеально уложенные волосы. Это ведь следы тщательного ухода. Сколько времени он тратит на это утром? А телефон, что он достал перед тем, как пожать мне руку. Ему вряд ли звонили. Скорее, он использовал его как зеркало, чтобы увидеть отражение и, если нужно, поправить укладку.</p>
<p>— Да, понял, — протянул я. — Да и со связями ты прав. Встречи со Спесивцевым я бы не хотел.</p>
<p>— Шаришь, чел. Вон Вика Смирнова, — кивнул он. — Королева школы. Со мной тусует. Присоединяйся.</p>
<p>Я проследил за его взглядом. В дверях стояла девушка. Стройная, с тёмно-каштановыми волосами. Её лицо было тонким, с правильными, почти кукольными чертами. Но главным были глаза. Большие, выразительные, с чуть приподнятыми внешними уголками, что придавало всему её облику какую-то кошачью грацию. Она смотрела прямо на меня. И улыбалась.</p>
<p>Нет, не так. Она не улыбалась. Она растягивала губы в улыбке, которая была чем-то совершенно иным. В этой улыбке читалось всё сразу: любопытство, оценка, превосходство, насмешка. И что-то ещё, что я не смог разобрать.</p>
<p>Я чуть было не сказал, что вот и черлидерша.</p>
<p>— Новенький, присоединяйся к нам, — с улыбкой хищницы произнесла она. — Может, на выходные в Пиранью сходим.</p>
<p>Её голос звучал сладко. И ядовито. Недавно я читал в журнале, что информация о том, что удав гипнотизирует жертву, перед тем как её съесть, — это миф. А вот Вика точно могла бы.</p>
<p>Я не знал, что такое «Пиранья». Кафе? Клуб? Какая-то местная достопримечательность? Но переспрашивать не стал. В её тоне прозвучало что-то такое, что делало любой уточняющий вопрос проявлением слабости. Я почувствовал, как внутри поднимается волна отвращения.</p>
<p>Я улыбнулся в ответ. Потому что так было проще.</p>
<p>— Хорошо, — сказал я. — Как-нибудь.</p>
<p>К счастью, перемена была короткой, и я отправился за остальным классом к новому кабинету.</p>`,
    15: `<p>Оставшийся день пролетел незаметно.</p>
<p>На переменах знакомился со своим классом. Как и сказал в начале, имён я почти не запомнил. Слишком много нового за столь короткий промежуток времени.</p>
<p>На уроках писал в тетради рассказ о метели, о Волге, прокручивая в голове воспоминания про тот демонический стробоскоп из окон. То и дело украдкой поглядывал на ту одноклассницу с русыми волнистыми волосами. Она сидела на второй парте через одну, и на истории, и на английском. Я пытался запомнить, с кем она разговаривает, как смеётся, какие тетради у неё в рюкзаке. Пытался найти что-то, что помогло бы мне начать разговор. Но момент был упущен. Та короткая встреча взглядами на физике осталась позади, и я откровенно стеснялся подойти. Что я скажу? Привет, я Ярослав, я новенький, и мне показалось, что мы знакомы всю жизнь? Звучит как бред. Как строчка из пошлого романа. Нет. Нужно придумать что-то другое. Что-то естественное.</p>
<p>Но ничего естественного в голову не приходило.</p>
<p>По окончании уроков быстро собрал вещи и поспешно направился к дому, стараясь не попасть на глаза Анатолию с его стаей гиен, как мысленно окрестил я их. Присоединяться к такой «тусовке» у меня желания не было.</p>
<p>Уткнувшись взглядом в асфальт, побрёл по дороге, прокручивая в голове события дня. Навязчивое предложение дружбы Анатолия. Его напыщенность, самоуверенность… Сладко-ядовитый голос Виктории. Интересно, сирены из Одиссеи выглядели также? Загадочный образ одноклассницы… Интересно, как её зовут? Я ведь хотел спросить кого-то из класса, потом испугался, что это вызовет какие-то дополнительные вопросы или ещё больше, начнут об этом сплетничать. Того парня с гриндерами, который курил возле школы…</p>
<p>Из размышлений меня вырвала неожиданная смена асфальта тремя парами ботинок, что появились из ниоткуда передо мной. Я поднял голову.</p>
<p>— Слышь, пацан, — произнёс тот, что стоял ближе всех. Его голос был хриплым. Он улыбался. — Дай позвонить.</p>
<p>Их было трое. Здоровые, на голову выше меня.</p>
<p>— А? — не придумав ничего внятного рефлекторно сказал я.</p>
<p>— Телефон, говорю, дай. Оглох? — повторил он и шагнул ко мне.</p>
<p>— У меня нет телефона, — сказал я, стараясь, чтобы голос звучал уверено.</p>
<p>— Пиздишь, — сказал второй. — Ты откуда вообще?</p>
<p>— Я… Из Москвы, — нелепо сказал я.</p>
<p>Какой кошмар. Что я только что ляпнул…</p>
<p>— О, Москвич! Вот это шара, — ухмыльнулся молчавший до этого третий. — Да лан, ты брось, всё норм. Смотри, у меня тоже мобила есть. Если боишься, вот, смотри. Просто лаве кончилось.</p>
<p>Ну вот, картина — Приплыли. Я уже представлял, как у меня выворачивают карманы, как забирают телефон, деньги, может, даже рюкзак. Как я возвращаюсь домой с разбитым носом и отец говорит — Ну и что, сам виноват, нечего было по дворам шляться. Всё это пронеслось в голове за долю секунды.</p>
<p>Они обступили меня плотнее. Я попятился назад, но споткнулся о бордюр, сделав себя ещё более беспомощным.</p>
<p>И в этот момент из-за угла показался он.</p>
<p>Тот самый парень в гриндерах. Тот, что курил у школьного забора утром. Высокий, худой, в тяжёлой кожаной куртке.</p>
<p>— Эй, пролетариат, — произнёс он, и в его голосе прозвучало столько спокойного презрения, что я на мгновение забыл о собственном страхе. — Отвали.</p>
<p>Троица развернулась к нему. Они явно не ожидали такого поворота.</p>
<p>— Чё ты сказал? Ты кто такой вообще? — сказал первый.</p>
<p>— Глухой? Это вы блядь откуда здесь?</p>
<p>— Чего ты там вякнул? — сказал третий, показывающий мне телефон, и сделал шаг по направлению к парню в кожаной куртке.</p>
<p>И тогда всё произошло очень быстро. Так быстро, что я даже не успел толком ничего разглядеть. Резким, поставленным движением кулак парня взметнулся и попал прямиком в челюсть тому, кто спросил про «вякаешь». Тот даже не вскрикнул, попятившись назад. Руками пытаясь поймать воздух, он сделал несколько шатающихся шагов и упал на асфальт. Рядом упал его телефон.</p>
<p>— У, сука, — пробормотал его друг и сделал шаг по направлению к парню в гриндерах. — Ты совсем ох…</p>
<p>И не успел он договорить, как получил размеренный, но молниеносный удар под дых.</p>
<p>Наступила гробовая тишина, разбавляемая лишь небольшими и прерывистыми постанываниями незадавшихся романтиков с большой дороги.</p>
<p>— Ну, хер ли вылупился? Следующий? — спокойно и буднично протянул мой неожиданный спаситель, обращаясь к последнему из троицы.</p>
<p>На лице того несколько мгновений отображался тяжёлый мыслительный процесс, но, видимо, он решил, что лучшая драка та, которая не состоялась. Он спешно помог подняться предводителю троицы и, взявши под руку получившего под дых, они ретировались.</p>
<p>Парень в гриндерах равнодушно проводил их взглядом, затем посмотрел на меня. Меня поразило его спокойствие. Было ощущение, что не произошло ничего экстраординарного. Он буднично достал сигарету и закурил.</p>
<p>— Ты чего, москвич? С люмпенами дела не имел? — сказал он спокойным голосом, выпуская дым.</p>
<p>Поразительный контраст, неожиданно подумалось мне. Он делает это так легко и непринуждённо, никакой бравады, как это было у Анатолия. Одна естественность.</p>
<p>— Я… Да… — неуклюже проговорил я, не зная, что сказать.</p>
<p>Впервые я разглядел его вблизи. Тёмные, коротко стриженные волосы. Потёртая кожаная куртка, в одном месте — аккуратная заплатка. Джинсы были рваными, но не из-за моды, а так, словно в них реально лазили через заборы.</p>
<p>— Слова — хорошее оружие. Но против трёх деградантов их недостаточно. Это, как говорится, добрым словом и пистолетом… Ну ты пытался.</p>
<p>Я хотел что-то сказать, но он тут же продолжил говорить.</p>
<p>— Я Максим, — он протянул мне руку.</p>
<p>Я пожал её. Рукопожатие у него было крепким.</p>
<p>— Я Ярослав.</p>
<p>— Я-я, — с немецким акцентом спародировал меня он, впервые улыбнувшись. И в этой улыбке внезапно проступила неожиданная, почти мальчишеская открытость. — Ладно. Мне идти надо. Дальше хоть сам-то дойдёшь?</p>
<p>— Да, спасибо, — мне стало ещё более неловко.</p>
<p>— Ну бывай, в школе увидимся.</p>
<p>Он кивнул и направился дальше по улице, оставив меня одного с колотящимся сердцем. Я был в такой степени взволнован, что даже не попытался его догнать. Хотя стоило бы как минимум нормально и внятно поблагодарить его. Он ведь по какой-то причине вступился за меня.</p>
<p>Всё произошло настолько стремительно, что я просто несколько минут так и продолжил стоять, испытывая странную смесь страха и восхищения.</p>`,
    16: `<p>Когда я пришёл домой, пахло свежеприготовленной едой.</p>
<p>Родители были на кухне. Отец решил заехать пообедать домой. Я быстро скинул куртку и зашёл в ванную, чтобы вымыть руки.</p>
<p>— Ну как первый день? — донёсся голос отца с кухни.</p>
<p>— Продуктивно и достопочтенно, — буркнул я, пытаясь скрыть своё до сих пор не прошедшее волнение, но вместе с тем испытывая лёгкое раздражение, которое очень удивляло меня. К счастью, отец не услышал. Думаю, я мог ответить что угодно, его всё равно не волновал мой ответ.</p>
<p>Пальцы меня не слушались, и я неуклюже выключил воду, сначала дёрнув смеситель в разные стороны. Вытер руки и вышел на кухню.</p>
<p>— Отлично. Кстати, так как Ярослав пришёл, могу уже и сказать. Оля, я там поговорил с руководством, смог договориться. С понедельника выходишь к нам. Пока секретарём, но это только начало.</p>
<p>Мать всплеснула руками, чуть не уронив тарелку, что держала до этого:</p>
<p>— Саша, правда? Спасибо огромное.</p>
<p>Они тут же заговорили о работе, о деньгах, о перспективах. Их голоса слились в один однотонный и ровный гул. Думая о том, что лучшего шанса не будет, я, пользуясь моментом, пробормотал что-то про уроки и быстро проскользнул в свою комнату.</p>
<p>Мне срочно нужно было выместить свои эмоции на бумагу. Потянулся к рюкзаку, чтобы достать спасительную тетрадь, полную важных мне мыслей. Мне хотелось описать весь свой сегодняшний день.</p>
<p>Раскрыл рюкзак. Учебник. Ручка. Учебник. Школьная тетрадь. Линейка. Учебник. Карандаш. Дневник… Сердце начало бешено колотиться в груди. Я вытряхнул всё содержимое рюкзака на кровать.</p>
<p>Её не было.</p>
<p>Холодная паника накатила волной. Я вновь заглянул в рюкзак, начал судорожно проверять даже карманы, в тот момент не задумываясь, что они как минимум меньше самой тетради. Даже заглянул под кровать, в иррациональной надежде отыскать тетрадь там.</p>
<p>Но нет. Я где-то её оставил. Кто-то сейчас читает все мои записи, всё, что я записывал и о чём размышлял. Это фиаско. Завтра надо мной будет смеяться, если не вся школа, то весь класс. Это будет позор.</p>
<p>В дверь постучали. Я вздрогнул.</p>
<p>— Ярослав, а ты есть-то будешь? — донёсся мамин голос.</p>
<p>— Я не хочу, — ответил я, стараясь, чтобы голос звучал нормально.</p>
<p>— Опять не хочу? Ярослав, ну так нельзя. Ты же ничего не ел.</p>
<p>— Я… Я потом. Ма, честно.</p>
<p>Пауза. Шаги. Мама ушла. Я остался сидеть на полу, в окружении учебников и вывернутого рюкзака, и чувствовал, как внутри меня поднимается отчаяние.</p>`,
    17: `<p>Я шёл в школу как на казнь.</p>
<p>Нет, это не было красивой метафорой или художественным преувеличением. Я действительно чувствовал себя приговорённым. Каждый новый шаг приближал меня к моменту публичного унижения.</p>
<p>Мой блокнот, моя тетрадь, — наверняка уже стала достоянием всего класса. Представлял себе это всё в красках. Вот Анатолий держит его в руках, зачитывая вслух мои записи, и его идеально поставленный голос разносится по коридору. Вот Вика слушает, приподняв бровь, на её губах играет та самая сладко-ядовитая усмешка. Вот остальные двадцать с лишним человек, чьих имён я даже не запомнил, смеются. Или не смеются, а переглядываются и с особым выражением лица, как когда ты испытываешь стыд за другого человека.</p>
<p>Я шёл и думал, что неплохо было бы сесть на поезд и уехать. Вот прям сейчас. Да. Развернуться, я помню, где вокзал, пойти туда, купить билет и исчезнуть. Не важно куда. Как будто меня не было. Просто уехать и нет проблем.</p>
<p>Отец, наверное, разозлится. Будет в ярости. Но это что? Впервые произойдёт? Пф, нет. Это я уже проходил, ничего нового.</p>
<p>Потом я подумал, что теоретически может всё и не так плохо. Может же быть, что его просто никто не нашёл? Я просто его где-то забыл, а потом пришла уборщица и выкинула его. Или просто где-то положила. Надо пройти быстро по всем кабинетам, где были уроки. Может, он так и лежит на одной из парт. А? Возможно же. Не знаю…</p>
<p>Я так погрузился в эти тягостные размышления, что даже не заметил, как прошёл весь путь к школе. Вот я уже подошёл к школьной калитке. Остановился, собираясь с духом. Сердце колотилось, в висках стучало. Отличный набор. Ладно, была не была, сделал шаг, и в этот момент меня окликнули.</p>
<p>— Ярослав!</p>
<p>Я вздрогнул. Обернулся.</p>
<p>Передо мной стояла та самая одноклассница с русыми волнистыми волосами. Та, чьё имя я так и не узнал. Она стояла в двух шагах от меня, чуть запыхавшаяся, словно догоняла, и смотрела прямо мне в глаза. На ней была лёгкая куртка, расстёгнутая, несмотря на холод, и шарф крупной вязки, небрежно наброшенный на плечи. Волосы чуть растрепались от быстрой ходьбы, и она машинальным жестом заправила прядь за ухо.</p>
<p>— Я Варвара, — сказала она просто.</p>
<p>— Я Ярослав, — машинально ответил я.</p>
<p>Блин, она же и так обратилась по имени…</p>
<p>— Ага, — рассмеялась она.</p>
<p>Смех у неё был лёгкий. Я и сам невольно улыбнулся.</p>
<p>— Ты вчера забыл, — сказала она.</p>
<p>И протянула мне мою тетрадь.</p>
<p>Блокнот. Мой блокнот. Вот он. Который я купил перед переездом. В который уже столько успел написать. Я смотрел на неё и не мог поверить. Это было похоже на чудо.</p>
<p>Словно боясь спугнуть, я аккуратно взял блокнот из её рук. Так и оставшись с ним стоять в полусогнутой руке, не зная, что сказать.</p>
<p>— Фух, — вырвалось у меня. — Хеппи энд. Уезжать не придётся. Позора избежал.</p>
<p>Я сказал это, кажется, вслух.</p>
<p>Варвара неожиданно добавила:</p>
<p>— Блин, написано вообще очень круто. Прости, я прочла. Просто не поняла, чья тетрадь, и открыла. А потом не могла остановиться. Ты классно пишешь.</p>
<p>Я замер. Слова застряли у меня в горле. Она прочла. Она прочла всё. Стоп. И она сказала, что это круто? Не странно? И не то, что я псих? И классно пишешь?</p>
<p>Смутился. Внезапно будто исчез весь воздух. Хотел что-то сказать. Уже открыл рот, чтобы поблагодарить её, сказать, что я… Но в этот момент меня прервал чужой голос.</p>
<p>— Варёчек, приветик.</p>
<p>Голос был громким, уверенным, и принадлежал он человеку, который явно не привык, чтобы его игнорировали. Я обернулся. К нам приближался парень. Высокий, спортивного телосложения. Средней длины стрижка, неяркое мелирование. На вид ему было лет двадцать, может, чуть меньше. Лицо у него было приятное, но что-то в нём настораживало. Какая-то слишком отрепетированная расслабленность. Слишком уверенная улыбка. Слишком прямой взгляд, который словно ощупывал тебя и выносил оценку.</p>
<p>— Саша, привет, — ответила Варвара нейтрально.</p>
<p>Я уловил в её голосе перемену. Только что она смеялась и была расслаблена, а теперь словно появился невидимый барьер.</p>
<p>— А ты что, с новыми друзьями прогуливаешься? — спросил Саша, переводя взгляд на меня. Его глаза скользнули по мне сверху вниз и обратно. Оценили. Взвесили. — Я думал, ты уже спешишь на урок.</p>
<p>Это была какая-то слишком светская беседа для таких декораций. Я хотел представиться. Протянуть руку. Сказать: «Привет, я Ярослав, новенький». Обычный вежливый жест, который разрядил бы обстановку. Но не успел. Потому что в этот момент, поравнявшись со мной, Саша одним быстрым движением выхватил блокнот из моих рук.</p>
<p>— Так, а что это у нас? — произнёс он с той особой интонацией, с которой взрослые обращаются к детям.</p>
<p>Я замер. Просто замер, словно моё тело забыло, как двигаться. Всё произошло настолько быстро, что я даже не успел среагировать. Только что блокнот был у меня в руках — и вот он уже в чужих. Снова.</p>
<p>Ну вот, подумал я. А ведь всё так хорошо начиналось.</p>
<p>Я стоял и смотрел, как он листает блокнот. Его пальцы — крупные, с коротко подстриженными ногтями — грубо перебирали страницы. Он не читал. Он проглядывал. Выхватывал отдельные слова, обрывки фраз. И комментировал их вслух, с той же снисходительной интонацией.</p>
<p>— Ага, стробоскопы... Скучаем по тебе... Метель... Фантаст, что ль? Ага…</p>
<p>Признаться, я настолько оторопел за эти несколько минут от смены вектора событий, что просто замер и не пошевелился. Полнейший ступор. Мой мозг словно заклинило. Сначала — ужас от мысли, что блокнот потерян. Потом — чудо: он нашёлся, и Варвара сказала, что я классно пишу. Потом — снова удар: какой-то незнакомый парень выхватывает его у меня и начинает читать. Амплитуда этих эмоций была слишком большой. Я не справлялся.</p>
<p>Стоял, как парализованный, и не мог даже рта открыть. И вместе с этим беспомощным оцепенением во мне росло смутное ощущение дежавю. Очень странное, почти мистическое. Как будто это уже было. Как будто я уже стоял вот так, глядя на чужую беспардонность и не в силах ничего сделать.</p>
<p>— Ага, цапля... — продолжал Саша, перелистывая страницы. — Волга... Зов... Ну прям мля Кинг у нас.</p>
<p>Мне нужно было срочно вернуть себе тетрадь. Я должен был что-то сделать. Что угодно. Но моё тело не слушалось.</p>
<p>Но я не успел ничего предпринять. Потому что Варвара сделала это за меня.</p>
<p>Одним ловким, точным движением она выхватила блокнот из рук Саши. Блокнот мелькнул в воздухе и оказался у неё.</p>
<p>— Саша, нельзя читать чужое, — сказала она.</p>
<p>Голос её звучал ровно, но в нём прорезалась сталь. Она смотрела на него в упор, и в её взгляде было что-то такое, отчего Саша, при всей своей массивности и уверенности, чуть отступил. Не физически. Но его поза чуть изменилась, словно он наткнулся на невидимую стену.</p>
<p>— У нас урок, — продолжила она. — Нам пора. Мы пойдём.</p>
<p>Она кивнула мне — коротко, но выразительно. И направилась ко входу в школу.</p>
<p>— Всего доброго, — на автомате сказал я и пошёл вслед за ней.</p>
<p>Двигался как робот. Ноги шагали, а сознание ещё не догнало тело. Я всё ещё был там, где этот парень листал мой блокнот. Всё ещё чувствовал, как кровь стучит в висках.</p>
<p>Через несколько секунд сзади нас раздался возглас:</p>
<p>— Варька, приходи! Буду тебя ждать!</p>
<p>Голос Саши звучал всё так же уверенно, но теперь в нём прорезалась какая-то другая нота. Не угроза. Скорее, настойчивость.</p>
<p>Варвара не обернулась. Она шла быстро, и её шаги по асфальту звучали чётко и решительно. Я заметил, что она раздражена.</p>
<p>Я, со своей стороны, был полностью обескуражен утренними событиями. Мой мозг всё ещё пытался переварить произошедшее. Блокнот потерян. Блокнот найден. Она прочитала. Она похвалила. Саша выхватил. Варвара выхватила. Всё это заняло от силы пару минут, но я чувствовал себя так, словно прожил за это утро целую жизнь. Поэтому я просто следовал за ней. Шагал и молчал.</p>
<p>Мы зашли в школу, подошли к гардеробу. Варвара остановилась, повернулась ко мне. Протянула блокнот.</p>
<p>— Не обращай внимания, — сказала она. — На Сашу. Он не плохой, он просто… Не обращай внимания.</p>
<p>Её голос звучал уже спокойнее. Раздражение уходило, сменяясь чем-то другим.</p>
<p>— Да без проблем, — ответил я, убирая блокнот в рюкзак. На этот раз — в самое надёжное отделение, на молнии. Туда, где его никто не достанет.</p>
<p>— Надо ускориться, — сказала она, бросив взгляд на часы на стене. — Николаевна нас на ноль умножит, если опоздаем.</p>
<p>Я кивнул, мы поспешили в сторону класса, как вдруг она резко остановилась. Выдохнула и улыбнулась.</p>
<p>— Ты чего? — спросил я.</p>
<p>Она посмотрела на меня. Прямо в глаза. Тем самым глубоким взглядом, который я не мог забыть со вчерашнего дня. Взглядом, в котором было что-то, чего я не встречал ни у кого раньше.</p>
<p>— Так я ж сама читала, — сказала она.</p>
<p>И всё. Больше ничего.</p>
<p>— Спасибо, — сказал я наконец. — Правда. Спасибо.</p>
<p>Она кивнула. И мы поспешили в кабинет.</p>`,
    18: `<p>Монотонно звучал голос Елены Николаевны, учительницы алгебры и геометрии, рассказывающей о темах. Пахло мелом и старым паркетом.</p>
<p>— …и, конечно, на экзамене вас ждут задачи на производные, на дифференцирование, — её голос был ровным, звучал почти безэмоционально. — Это основа. Без этого — никуда. Но это лишь инструменты. Как молоток и гвозди. Самое же интересное начинается, когда вы берёте этот инструмент и применяете его для понимания чего-то большего.</p>
<p>Она обвела класс взглядом и продолжила.</p>
<p>— Например, для понимания поведения функции на бесконечности. Или в точке, где она ведёт себя… странно. Для этого вам понадобится понятие предела.</p>
<p>Я почти не слушал, рисуя непонятные мне узоры на полях рабочей тетради. Точно, тетрадь. Потянулся к рюкзаку. Открыл молнию. Аккуратно достал её и провёл рукой по обложке, будто приветствуя старого друга. Открыл, пролистал до места, где остановился, и замер.</p>
<p>Рядом с текстом аккуратным, изящным почерком были выведены слова карандашом. Я пригляделся и понял, что это комментарии.</p>
<p>«Красиво описал ощущение холода. Чувствуется одиночество».</p>
<p>— Представьте прямую, — продолжала Елена Николаевна. — Бесконечную прямую. И на ней — точку. Вашу функцию можно запускать откуда угодно, гонять её по всей числовой оси, но её путь всегда будет вести к этой одной-единственной точке. Она будет колебаться, приближаться, почти касаться её…</p>
<p>Я дочитал до абзаца, где описывал, как чуть не шагнул в тёмную воду Волги. И рядом увидел аккуратно выведенный вопрос, который поразил меня тем, что в нём на всё смотрелось с совершенно другой стороны.</p>
<p>«А что, если река не хочет утопить? Что, если она просто хочет, чтобы её услышали?»</p>
<p>— Она никогда её не достигнет, — голос учителя продолжал объяснение темы, и в классе наступила мимолётная тишина. — Но весь её смысл, вся её суть — в этом стремлении. В этом бесконечном движении к чему-то. Понимаете? Функция обретает свой смысл только тогда, когда у неё есть этот предел. Точка, которая придаёт направление всему её пути.</p>
<p>Я поднял глаза и посмотрел на Варвару. Она что-то вновь рисовала в своей тетради. Опустил глаза на её комментарии. И внутри стало тепло. Впервые за долгое время я чувствовал не холод и не одиночество, а что-то, что согревало меня изнутри.</p>
<p>Она прочла. Но дело было даже не в этом. Она ответила.</p>
<p>— Ну, давайте уже решим пару задач, вам нужно готовиться к экзаменам, — раздался вновь голос учителя. — Записывайте…</p>`,
    19: `<p>Я вышел из школы, погружённый в свои мысли.</p>
<p>Автоматически повернул в сторону дома, и через некоторое время мой взгляд, привыкший уже к серости панелек, выхватил знакомый силуэт.</p>
<p>Варвара. Она шла впереди меня, её волосы развевались на ветру. Сердце снова принялось бешено колотиться. Я почти побежал, чтобы её догнать. В этот момент у меня ещё не было плана, но мне безумно хотелось с ней поговорить. Сказать что угодно, лишь бы начать разговор.</p>
<p>— Варвара! — выпалил я, поравнявшись с ней.</p>
<p>Она обернулась, и на её лице мелькнуло лёгкое удивление, сменившееся приятной улыбкой.</p>
<p>— Ярослав.</p>
<p>— Я… Я просто ещё раз хотел поблагодарить. Спасибо. Спасибо за тетрадь. Если бы её кто-то нашёл, то мне, конечно, бы… В общем, спасибо!</p>
<p>— Да брось, — она махнула рукой. — Мне наоборот неловко. Ты прости, я не хотела читать. Просто, найдя тетрадку, я подумала, чья это. И решила открыть, может, изнутри подписана. И просто прочла пару строчек. Мне так… показалось, будто, знаешь, я уже это читала. Или видела. Ощущение чего-то очень знакомого, понимаешь? Про метель, про Волгу. Но больше ничего не читала, честное слово! — она весело засмеялась.</p>
<p>Её смех был лёгким и приятным.</p>
<p>— Я иду в художественную школу, — сказала она, показывая вперёд. — Тут недалеко.</p>
<p>— О, а я тут рядом живу.</p>
<p>— Проводишь? — неожиданно спросила она.</p>
<p>Я замер на полсекунду. Художка. Художественная школа. Я понятия не имел, в какой стороне она находится. Да и какая, в сущности, разница. Она спросила. Она хочет, чтобы я пошёл с ней.</p>
<p>— Конечно, — ответил я. — С удовольствием.</p>
<p>Слова вылетели так быстро и так искренне, что я сам удивился. И тут же почувствовал, как кровь приливает к лицу. Не просто краснею — становлюсь багряным и пунцовым. Хорошо, что она в этот момент смотрела вперёд и не видела моего лица. Хотя, может, и видела. Но ничего не сказала.</p>
<p>Наша беседа была полна общих фраз, мы обсуждали учителей, домашнюю работу, как прошёл сегодняшний день, с какими моментами на каких-либо предметах у нас возникали сложности. И неожиданно для себя, видимо, чувствуя эту непринуждённость, я задал вопрос.</p>
<p>— Варвара, а почему… Почему твои родители выбрали для тебя именно художественную школу?</p>
<p>Она посмотрела на меня с искренним, неподдельным удивлением. Было ощущение, что я спросил, почему она ходит на двух ногах.</p>
<p>— Почему родители? — переспросила она.</p>
<p>— Ну, как, — смутился я. — Это же родители в основном выбирают, куда отдавать детей. Музыкальная школа, художественная. Спорт. Может, что-то ещё, не знаю. Вот я раньше ходил на плавание. Это же, типа, полезно. Потом нужно было идти в спортшколу, но, к счастью, отец сказал, что так я завалю успеваемость и никуда не поступлю.</p>
<p>— А-а, — протянула она, и её удивление сменилось лёгкой грустью. — Нет, Ярослав. Не родители. Я сама. Ну я с детства люблю рисовать. Это началось ещё в детстве…</p>
<p>И она внезапно засмеялась.</p>
<p>— Что такое? — спросил я, не зная, чего испугался.</p>
<p>— Да я вспомнила, — продолжая смеяться, сказала она. — В детстве я дома все обои изрисовала, пока никого не было. Было, конечно, потом не до смеха. Но я всё равно не смогла остановиться. Когда я рисую, я чувствую себя именно собой. Звучит глупо, но это именно так.</p>
<p>— Нет, вообще не глупо, — понимающе сказал я.</p>
<p>Именно так я себя и чувствовал, когда писал что-то в тетрадь. Но об этом рассказать ей я постеснялся.</p>
<p>— Вот я и выбрала художку. Почему же родители должны это решать?</p>
<p>Её простой вопрос повис в воздухе, показавшись мне таким гениальным, что у меня перехватило дыхание от его неожиданности. То есть, как это «почему»? А ведь… Почему, действительно, почему?</p>
<p>— То есть… То есть ты просто занимаешься тем, чем нравится?</p>
<p>И мой голос прозвучал так тихо, будто я только что открыл сам для себя что-то невероятное.</p>
<p>— А как же иначе? — её удивление было абсолютно естественным. — Ты же можешь быть собой. А жить чужую жизнь — скучно. И зачем?</p>
<p>Так увлёкшись разговором, я не заметил, как мы подошли ко входу в художественную школу. Быть собой. Жить чужую жизнь. Слова повторялись эхом в моей голове. Я остановился, как будто пытаясь понять её такие простые и одновременно непостижимые слова.</p>
<p>Я посмотрел на неё, на её спокойное и светлое лицо, на глубокие и выразительные глаза, и вдруг почувствовал то самое странное чувство… Будто целостность. Каждый день я просыпался с ощущением, что внутри меня, где-то, чего-то, а я и сам не знал, чего, не хватает. Казалось, где-то есть пустоты. А сейчас, рядом с ней, я словно был не заполнен, нет, а именно целым. И впервые за такое долгое время я мог говорить, не подбирая слова, не пытаясь говорить на языке собеседника. А быть собой и говорить то, что я думаю.</p>
<p>И эти чувства были невероятно тёплыми и согревающими.</p>
<p>— Спасибо тебе, — неожиданно и для неё, и для себя сказал я.</p>
<p>— За что?</p>
<p>— За компанию, — не решаясь сказать правду, ответил я. Хоть и думал совершенно о другом.</p>
<p>— Это тебе спасибо, Ярослав, — она поправила сумку на плече. — До завтра!</p>
<p>— До завтра.</p>
<p>Стоял и смотрел, как она заходит в двери художественной школы, скрываясь внутри. И тепло не уходило, нет. Оно словно разливалось по всему телу. Я не знал, что именно важно, но в этот момент понял, что произошло нечто невероятно важное.</p>`,
    20: `<p>Мне не хотелось домой.</p>
<p>Я стоял у дверей художественной школы и понимал, что не сейчас. Во мне всё ещё пульсировало то тепло, которое появилось, когда мы шли рядом. И я боялся, что дома оно исчезнет.</p>
<p>Поэтому я развернулся и пошёл в другую сторону. Не домой. Просто куда глаза глядят.</p>
<p>Брёл через дворы, вышел к большой дороге. Вдоль неё, к мосту через железную дорогу. Город постепенно менялся. Панельные дома спального района сменялись на сталинки с эркерами и лепниной.</p>
<p>Я вспоминал её комментарии. Вспоминал, как она сказала, что я классно пишу. Даже несколько раз это вслух повторил. Это было невероятно. Как будто она дала мне ключ от двери, которую я сам закрыл много лет назад. И уже даже забыл, где он находится.</p>
<p>Но чем дольше я об этом думал, тем больше к теплу примешивалось что-то другое. Холодное и скользкое. Я вспомнил утро. Саша. Тот самый парень, что вырвал мой блокнот. Его приторный голос. Как он сказал? «Варька, приветик»? Нет, даже не так. По-другому. Варёчек. Какая же мерзость. Меня передёрнуло даже сейчас.</p>
<p>И я… Нюня! Ничего не сделал. Он вырвал тетрадь из моих рук. Читал мои же записи! А я стоял. Ничего не делал. Разинул рот. Господи, тюфяк. Почему, почему я ничего не делаю?</p>
<p>Ведь Варвара не стояла, она в итоге выхватила обратно блокнот. Быстро, ловко, уверенно. Она, а не я. Хотя должно было как раз наоборот. Позор.</p>
<p>Я испытал злость. Глухую, тягучую, поднимающуюся откуда-то из живота. Злость на Сашу. Злость на себя. Злость вообще на мир. Всё идиотски, а я главный идиот.</p>
<p>Но тут же одёрнул себя. Зачем мне об этом думать? Какая мне разница, кто он такой? Почему меня вообще это волнует, как меня касается? Кто мне эти люди? И главное, кто я им?</p>
<p>Я тряхнул головой, отгоняя мысли. Не сейчас. Сегодня был хороший день. Не нужно портить его дурацкими мыслями.</p>
<p>На перекрёстке повернул направо и замер. Передо мной возвышалась монументальная арка. В ней было темно и тянуло холодом, тем особым холодом, который бывает только в старых местах, куда никогда не заглядывает солнце.</p>
<p>Я уже хотел пройти мимо, но увидел лестницу. Она уходила вниз. Над лестницей виднелась вывеска — «Книжный магазин».</p>
<p>У меня не было какой-то конкретной цели, скорее любопытство. Я спустился по лестнице, открыл стеклянную дверь и почувствовал его. Запах. В нос ударил знакомый и так мною любимый запах бумаги, чернил, переплётов книг. В нём всегда есть какой-то непередаваемый шарм. Этот запах всегда предвосхищал что-то новое. Каждый раз, покупая книгу или беря её из библиотеки, я словно прислушивался к ней, вдыхая эту смесь из разных ароматов.</p>
<p>Магазин оказался огромным. Гораздо больше, чем можно было предположить снаружи. Он уходил в глубину подвала длинными лабиринтами стеллажей, которые терялись где-то в полумраке. Высокие, до самого потолка, забитые книгами так плотно, что, казалось, ещё один том — и они рухнут под собственной тяжестью. На полках стояли не только новые издания, но и старые, с потёртыми корешками, с золотым тиснением, с кожаными переплётами.</p>
<p>— Впервые у нас? — раздался тихий голос.</p>
<p>Я обернулся и увидел прилавок кассы. У него стояла невысокая пожилая женщина в очках, за которыми виднелись спокойные и ясные глаза. Также я обратил внимание на её серебряные серёжки в виде письменного пера.</p>
<p>— Да, — ответил я. — Случайно вас нашёл.</p>
<p>— Не бывает случайностей, — улыбнувшись, мягко сказала она. — Особенно сегодня. У нас читательский день. Смотрим кино. Показы для своих. Но раз ты интересуешься книгами, то точно из своих. Останешься?</p>
<p>Возвращаться до вечера домой мне не хотелось. Я кивнул.</p>
<p>— Отлично! Проходи вон туда, видишь, где расставлены стулья? Садись. Мы как раз скоро начинаем.</p>
<p>В глубине зала стеллажи расступались, образовывая некое подобие импровизированного актового зала. Там были расставлены ряды складных стульев и натянута белая простыня вместо экрана. Тускло светил проектор, отбрасывая пыльные дорожки в воздухе. Зрителей было человек десять, каждый сосредоточенно смотрел на экран, и все они молчаливо ожидали начала показа.</p>
<p>Я пристроился с краю, и через некоторое время свет погас. На экране поплыли кадры дворов Москвы. Я сразу их узнал. Съёмка была любительская, дрожащая, будто из чьих-то домашних архивов.</p>
<p>Вдруг на экране промелькнул я, идущий по улице с портфелем. Я, тот, который в реальности, вздрогнул от неожиданности.</p>
<p>Кадры сменились. Я увидел привычную мне школу изнутри, где учился в Москве. Знал каждый сантиметр этих стен. Школьный коридор. Там снова был я, меня прижали к стене три старшеклассника. Их лица были размыты, но я помнил эти черты как сейчас. Сопротивляться было бесполезно. Экзекуции проводились с каждым. Поочерёдно. Кому-то просто выпадал несчастливый билет.</p>
<p>Главный, Андрей, тыкал мне пальцем в грудь. Я не смотрел ему в глаза, уставившись в пол. Мои губы шевелились, бормотав какие-то оправдания. В этот момент он выхватил из моих рук тетрадку. Я её помнил, писал в неё рассказы. Попытавшись её вернуть, я получил сильный тычок. Он начал её листать, зачитывать и хохотать. Мимо проходили другие ученики. Кто-то равнодушно шёл дальше, кто-то останавливался, слушал и хихикал.</p>
<p>В зале была тишина. Я огляделся. Силуэты людей на стульях сидели неподвижно, их лица скрывала темнота. Ни смешка, ни удивлённого шёпота. Только равномерный гул проектора. Казалось, что все увлечены просмотром и не видят никаких странностей в происходящем.</p>
<p>На экране продолжалось «избиение младенцев». Андрей начал передавать мою тетрадь, и каждый, взяв её, кривляясь, зачитывал какой-то из отрывков. Я видел, как тот я из прошлого, на экране, краснеет и нелепо пытается забрать тетрадку. Крупным планом показалось моё лицо — испуганное и униженное. Я помнил этот случай. Этот страх быть осмеянным всегда оставался со мной.</p>
<p>Кровь прилила в висках, и стало трудно дышать. В книжном магазине словно стало жарко, и стены будто сжались. Мне хотелось встать и уйти, но я не мог, пригвождённый к стулу этим позором.</p>
<p>Тетрадь вернулась в руки Андрея, и он с особенным пафосом начал читать отрывок одного из моих любимых рассказов. Я писал его про капитана морского корабля, подражая «Одиссее» Капитана Блада.</p>
<p>От ужаса и стыда я закрыл глаза. Как вдруг его кривляния закончились, наступила тишина. Вновь открыв глаза, я увидел молчаливо стоящего и не двигающегося Андрея. Он медленно, очень медленно повернулся и посмотрел прямо в объектив камеры. Прямо на меня. Его глаза были чёрными. И пустыми.</p>
<p>— Ярослав, — его голос прозвучал механически чётко, безэмоционально, но заглушая проектор. — Ярослав, мы скучаем по тебе.</p>
<p>Я замер, сглотнув и боясь шевелиться.</p>
<p>Вдруг на экране Андрей начал улыбаться. Его улыбка растянулась до неестественных размеров, превращаясь в какой-то хищный оскал и обнажая нечеловеческие зубы, похожие на клыки мифического зверя.</p>
<p>— Ты думал, что нас оставишь? Сбежишь? — сказал он, надвигаясь ближе к объективу. Его фигура исказилась, словно помехами, стала размытой и поплыла. — Мы всегда будем рядом. Всегда будем смеяться над тобой.</p>
<p>Я сидел, не в силах пошевелиться, как будто под гипнозом от происходящего.</p>
<p>— Всегда будем смеяться над тобой, — повторил он голосом машины, искажаемой помехами. Его лицо стало покрываться сетью чёрных трещин, будто фарфор. Из трещин сочилась чёрная маслянистая жидкость. Он сделал ещё шаг, и его голова и рука уже находились вне экрана, в реальности.</p>
<p>— ПОКА НЕ УБЬЁМ ТЕБЯ! — внезапно громко прокричал он, и его слова эхом раздались по книжному магазину.</p>
<p>Я рванулся с места, опрокидывая стул. Острая боль пронзила голень. Зацепившись за торчащий крепёж складного стула, я разорвал штанину. Не обращая на это внимания, я огляделся.</p>
<p>Зал был пуст. Стулья стояли ровными рядами, на которые падал свет от проектора. Но на них не было людей. На них сидели лишь груды тёмной, шевелящейся тины, с виду напоминающие человеческие фигуры. А вместо книг на полках лежали обрывки обоев, штукатурки, какие-то инструменты и что-то больно напоминающее кости. Людей или животных?!</p>
<p>Андрей, или то, что было Андреем, выплыл из экрана проектора и упал на пол с противным шлепком. Он поднялся, его конечности неестественно изгибались и двигались с какой-то насекомоподобной резкостью. Он загоготал леденящим смехом. Смех эхом разносился по помещению.</p>
<p>— Беги, графоман. Беги!</p>
<p>И я побежал. Не разбирая пути, не понимая, бегу ли я к выходу или бегу только вглубь этого подвала, ныряя мимо стеллажей, которые теперь были набиты разным строительным мусором. Хлюпающие шаги раздавались сзади меня, постепенно становясь всё ближе. Пробегая, я увидел кассу, где меня встретила продавщица. Прилавок кассы превратился в разделочный стол, на нём виднелись окровавленные туши разделанных птиц. Всё вокруг было в залитых кровью перьях.</p>
<p>Я увидел свет и лестницу на выход, и рванул к ней из последних сил. Бежал, задыхаясь, чувствуя приближающееся ледяное дыхание. Вот она, лестница! Чуть-чуть, чуть-чуть… Только не останавливаться.</p>
<p>Стеклянная дверь не была стеклянной. Это была приоткрытая старая железная дверь с засовом и огромным слоем ржавчины. Я врезался в неё плечом, она со скрипом поддалась, и я вывалился наружу.</p>
<p>Взлетел по ступенькам, хватая ртом ледяной уличный воздух, не чувствуя больше ничего. Споткнулся о последнюю ступеньку и упал, распластавшись на мокром асфальте. В ужасе поднял голову и обернулся назад, на вход в подвал.</p>
<p>Никакой вывески над ним не было. Внизу лестницы была заколоченная старая дверь с табличкой «ЗАКРЫТО», криво висевшей на одной петле.</p>
<p>Я выдохнул и поднялся. Колени дрожали. Вся одежда была в пыли и грязи. Возле рваной дырки на штанине было пятно от крови. На плече куртки отпечатался огромный слой ржавчины. Попытался отряхнуться, но руки не слушались меня.</p>
<p>— Отец меня убьёт за мою одежду, — подумалось мне, и я направился к дому.</p>`,
    21: `<p>Я шёл в школу, вжимая плечи от ветра, а может — от чего-то большего. Апрель, а до сих пор так и не потеплело.</p>
<p>Плечо всё ещё ныло от вчерашнего удара о ржавую дверь, а на ноге под тканью джинсов зудел затягивающийся порез.</p>
<p>Вчерашний вечер крутился в голове, раз за разом прокручивая воспоминания о том, как я до ночи пытался отстирать куртку в ванной. Вода стала бурой, но ржавчина всё никак не отмывалась. Потом в ванну зашёл отец. Его лицо выражало крайнюю степень разочарования. Он молча протянул мне иголку и нитки.</p>
<p>— Научись самостоятельно отвечать за последствия своих действий, — сказал он, и в его словах даже не было злости. Только давящее презрение. — Или бездействий. Вещи надо беречь. Они денег стоят. Хоть с ниткой и иголкой научишься обращаться, а то без нас помрёшь беспомощным.</p>
<p>Эти слова жгли сильнее, чем рана на ноге. Я хотел ему сказать про подвал, про чертовщину, которая здесь творится, и никому до неё нет дела, а все его размышления — это идиотские нравоучения про действия и инженерию, которые он бесконечно талдычит. Но промолчал. Как всегда молчу. Как молчал в прошлом, как молчал в настоящем. Как при старшеклассниках. Как при Саше. Как при нём. И от этого было тошно.</p>
<p>Каждый прокол иголкой и каждый неумелый кривой стежок, казалось, подчёркивал это раздражающее чувство внутри меня. Какая глупость. Повёлся на этот подвал. Потом испугался. Потом убежал. С другой стороны, а что я сделаю против этого кошмара? Всё это было реально.</p>
<p>На одном из столбов висело объявление. Я остановился, чтобы прочесть.</p>
<p>ПРОПАЛ БЕЗ ВЕСТИ</p>
<p>Белая бумага, изрядно выцветшая и размокшая от постоянной влажности, казалась старой, но я готов был поспорить, что раньше не видел её. Полупрозрачная фотография с подтёкшими чернилами. Фотография другого парня. Подпись — Сергей, 17 лет. Неуверенное лицо и ниже перечисление примет. Просьба сообщить, но контакты отсутствовали, как и дата. Произошло это недавно или давно?</p>
<p>— Куда они пропадают? — шёпотом проговорил я.</p>
<p>Это какой-то маньяк или их затягивает в такие же подвалы, где я был вчера? Их заманивают в книжные магазины? Только навсегда. Неожиданно испытал чувство вины. Можно ли было им как-то помочь? Можно ли было их спасти? Но тут же успокоил себя, что я здесь ни при чём, это не является моей виной, ведь я их даже не знаю. Но кто-то… Кто-то же должен их действительно искать. И заметить, что это не единичный случай. Почему этого не происходит?</p>
<p>А вчерашнее… Вчерашнее не было галлюцинацией. Не могло быть. И куртка, и штаны — были тому доказательствами. Машинально потрогал стежки шва на штанине.</p>
<p>Подумал о Варваре. Интересно, что она сказала бы, если бы знала? «А что, если река не хочет утопить?» — написала она. А подвал? Подвал-то явно хотел. Но почему?</p>
<p>Я не знал. И от этого было ещё страшнее.</p>
<p>Зашёл в школу, машинально поздоровался с вахтёршей и поднялся по лестнице на второй этаж. Вошёл в класс и сразу прошёл на своё место — последняя парта у стены. Здесь я почувствовал себя в относительной безопасности. Спина прикрыта, никто не подкрадётся сзади, видно всех. Я сел, достал учебник, тетрадь, ручку.</p>
<p>Непроизвольно мой взгляд отыскал Варвару. Она сидела на своём месте — вторая парта. Свет из окна падал на её волосы, и они казались почти золотыми. Она что-то записывала в тетради, сосредоточенно нахмурившись. На секунду подняла голову, и наши взгляды встретились. Я быстро отвёл глаза, чувствуя, как краснею.</p>
<p>Мне очень хотелось заговорить с ней. Но что сказать?</p>
<p>— Привет, Варвара! Представляешь, вчера я зашёл в несуществующий подвал с книгами, там за мной гнался оживший кошмар из моего прошлого, вылезший из проектора. Потом я до ночи стирал куртку и зашивал штанину. А как твой вечер?</p>
<p>Звучит как билет в сумасшедший дом.</p>
<p>Я сидел и молчал. Снова молчал. Как всегда.</p>`,
    22: `<p>В класс вошла Галина Петровна. Это была высокая женщина лет сорока с острыми чертами лица и короткой стрижкой. Начался урок.</p>
<p>— Здравствуйте, садитесь, — сказала она, кладя журнал на стол. — Сегодня мы будем писать эссе-рассуждение. Тему я напишу на доске.</p>
<p>Она взяла мел и размашистым, уверенным почерком вывела два слова: «Сила слова».</p>
<p>— Это тема, — повторила она, поворачиваясь к классу. — Не просто «слово», не просто «речь». Я хочу, чтобы вы подумали и написали, что для вас значит сила слова. Может ли слово быть оружием? Может ли оно быть щитом? Может ли оно быть созидающей силой? Или разрушительной? Вспомните литературные примеры, исторические, если хотите — личные. Но главное — чтобы вы думали. Не пересказывали учебник, а размышляли.</p>
<p>— Пф, — фыркнула Вика, вертя в руках дорогую ручку и не глядя на учителя. — Сила слова. Сила в деньгах, сила в связях.</p>
<p>— Почему ты так считаешь, Вика? — обратилась к ней Галина Петровна.</p>
<p>— Галина Петровна, ну представьте, за вами ухаживает два мальчика. Один мастер слова, а другой успешный. Кого выберете?</p>
<p>Анатолий, который сидел рядом с ней, снисходительно хмыкнул, как бы подтверждая её правоту.</p>
<p>— Вот мой отец, — сказал он, — мой отец, к примеру, если что-то и пишет, то это отчёты. Там, ну да, слова имеют вес. Потому что они о действиях. Цифры, факты, отчёты. Кто-то делает, а кто-то говорит.</p>
<p>— Хорошо, может быть и так. У вас сорок минут. Докажите, аргументируйте ваше мнение. Впереди экзамены. И я хочу, чтобы вы не только могли решать тесты, а умели рассуждать.</p>
<p>Меня окатила волна отвращения. Я вспомнил отца. Благодаря людям дела вращается мир. Дела. Не слова. Дела. Инженеры делают. Всё одно. Но только без слова не было бы ни отчётов, ни денег, ни инженеров, ни мира, каким мы его знаем.</p>
<p>Я взял ручку и начал писать.</p>
<p><em>В начале было Слово. </em></p>
<p><em>Эту строчку я помню с детства. Даже когда я не понимал её смысл, я её знал. Мой отец же считает, что слова не нужны, что нам намного важнее действия. Он любит повторять: «Благодаря людям дела вращают мир». Но как забавно, что и это предложение — это слова. Его мир видится ему как действие, осязается, как материал, будь то камень, дерево и металл. Их можно потрогать, значит, они существуют. Рене, привет! Я же, с моими заметками или рассказами, кажусь ему никем. Создатель макулатуры. Брось пустые слова и сделай что-то. </em></p>
<p>Ручка скользила по бумаге. Я писал всё, что так долго копилось во мне.</p>
<p><em>Но я вижу иное. Я чувствую другое. </em></p>
<p><em>Его действия, как считает он, являются словами. Не являясь материальными, будучи невидимыми, они могут ранить. Они могут заставлять сомневаться. Возводя стены, которые в разы больше, чем все построенные стены из камня. Его слова становятся моей реальностью. Его оценки из слов управляют моими действиями. </em></p>
<p>Мысли об отце, о метели, о Варваре, о вчерашнем ужасе — всё это превращалось в слова и обретало смысл. Я вспомнил Максима. Слова — хорошее оружие. Но против трёх деградантов их недостаточно. Он был прав. Против трёх гопников слов недостаточно. Но, парадоксально, а против чего-то большего?</p>
<p><em>И я понял, слово — это не звук. Это уже поступок. Поступок, направленный прямиком в сознание другого. </em></p>
<p><em>История мира — это не история молчаливых действий. Молчаливый подвиг, совершённый в абстрактном вакууме, при идеальных условиях, как в физике, не становится примером. Он так и остаётся в пустоте идеальных условий вместе с тем, кто его совершил. Безымянный солдат, совершивший подвиг, — не становится героем, он остаётся безымянным, пока о нём не расскажут, не высекут его имя на камне материальности. Словом. Гагарин, первый человек в космосе, был бы строчкой в журнале, а не легендой, если бы о нём не рассказали. </em></p>
<p><em>Взгляните на всё, что меняло ход истории. Всё это было сделано словом. Слово — семя. Действие — дерево, которое из него вырастает. Но без семени нет и дерева. </em></p>
<p><em>Есть слова, которые словно оружие. Есть слова, будто щит, которые защищают нас. Слово может быть хлебом. Пища телесная, пища духовная. </em></p>
<p>Я остановился. Перечитал и задумался. А как же моё молчание? Молчаливое согласие и неумение возразить…</p>
<p><em>А как же тишина, спросите вы? Тишина — это тоже слово. Молчаливое согласие со злом превращается в действие. Но молчание никогда не несло света, оно вело нас в темноту. Молчание — золото, скажете вы? Но тьма — это лишь отсутствие света. </em></p>
<p><em>Слово — величайшая сила, данная человеку. Это отличает нас от роботов, от безмолвных механизмов, от инстинктивного существования и приближает нас к тому самому Началу, где всё и началось. Где в начале было Слово. </em></p>
<p><em>И поэтому я люблю Слово. </em></p>
<p>Я поставил точку и выдохнул. Посмотрел на часы — прошло почти сорок минут. В классе стоял привычный рабочий шум: кто-то ещё писал, кто-то уже закончил и перешёптывался с соседом, кто-то украдкой поглядывал в телефон под партой. Анатолий, ухмыляясь, что-то рассказывал Вике, активно жестикулируя. Она смеялась, откидывая голову назад.</p>
<p>Прозвенел звонок. Резкий, пронзительный. Все зашевелились, засобирались. Галина Петровна поднялась из-за стола и сказала, перекрывая шум:</p>
<p>— Сдаём тетради. Оценки узнаете на следующем уроке.</p>
<p>Посмотрел на свою тетрадь и задумался: что скажет Галина Петровна? Что сказал бы отец, если бы увидел эти строки? Он бы, наверное, снова назвал их макулатурой. Но разве это должно быть для меня важным? Ведь на самом деле я знаю, что это не макулатура. Это — я.</p>`
};

// === ПОСТРОЕНИЕ МАССИВА ГЛАВ ИЗ HTML ===
const items = document.querySelectorAll('.contents-item');
const chapters = Array.from(items).map((item, index) => {
    const num = String(index + 1).padStart(2, '0');
    const raw = item.textContent.trim();
    const title = raw.replace(/^\d+\s*[•\s]*/, '').trim();
    const text = chapterTexts[index] || `<p class="placeholder">Глава в процессе написания…</p>`;
    return { number: num, title, text };
});

// === ОБРАБОТЧИКИ НАВИГАЦИИ ВНУТРИ ГЛАВЫ ===
document.querySelector('.nav-prev').addEventListener('click', () => {
    if (currentChapter > 0) openChapter(currentChapter - 1);
});
document.querySelector('.nav-next').addEventListener('click', () => {
    if (currentChapter < chapters.length - 1) openChapter(currentChapter + 1);
});
document.querySelector('.nav-contents').addEventListener('click', () => {
    chapterScreen.classList.remove('visible');
    setTimeout(() => {
        contentsScreen.classList.add('visible');
    }, 500);
});

// === ДЕЛЕГИРОВАНИЕ НА ОГЛАВЛЕНИЕ ===
contentsScreen.addEventListener('click', (e) => {
    const item = e.target.closest('.contents-item');
    if (!item) return;
    const idx = parseInt(item.dataset.chapter, 10);
    if (!isNaN(idx)) openChapter(idx);
});

// === КЛАВИАТУРА ===
document.addEventListener('keydown', (e) => {
    if (!chapterScreen.classList.contains('visible')) return;
    if (e.key === 'ArrowLeft' && currentChapter > 0) {
        e.preventDefault();
        openChapter(currentChapter - 1);
    }
    if (e.key === 'ArrowRight' && currentChapter < chapters.length - 1) {
        e.preventDefault();
        openChapter(currentChapter + 1);
    }
    if (e.key === 'Escape') {
        e.preventDefault();
        chapterScreen.classList.remove('visible');
        setTimeout(() => contentsScreen.classList.add('visible'), 500);
    }
});

// === ИНТРО: КАСАНИЕ / КЛИК / СВАЙП ===
let touchStartY = 0;

document.addEventListener('touchstart', (e) => {
    touchStartY = e.touches[0].clientY;
}, { passive: true });

document.addEventListener('touchend', (e) => {
    if (isStarted) return;
    const diff = touchStartY - e.changedTouches[0].clientY;
    if (diff > 50) startSequence();
}, { passive: true });

document.addEventListener('click', () => {
    if (!isStarted) startSequence();
});

// === ФУНКЦИИ ===

function startSequence() {
    if (isStarted) return;
    isStarted = true;

    // 1. Убираем картинку
    coverScreen.classList.add('hide-up');

    // 2. Показываем текст
    setTimeout(() => {
        textScreen.classList.add('visible');
        glitchText.classList.add('visible');

        // 3. Мигание
        setTimeout(() => {
            glitchText.classList.add('blinking');

            setTimeout(() => {
                glitchText.classList.remove('blinking');

                // 4. Глитч с затуханием в тьму — 2 секунды
                glitchText.classList.add('glitching');

                // Затухаем text-screen параллельно с глитчем
                setTimeout(() => {
                    textScreen.style.opacity = '0';
                }, 1200);

                // После окончания глитча — чёрный экран
                setTimeout(() => {
                    textScreen.classList.remove('visible');
                    textScreen.style.opacity = '';

                    // Показываем финальный чёрный экран
                    finalScreen.classList.add('visible');

                    // 5. Через 1.5 секунды — показываем название
                    setTimeout(() => {
                        // Затухаем чёрный экран
                        finalScreen.classList.remove('visible');

                        // Показываем название
                        titleScreen.classList.add('visible');

                        // Ждём клик для перехода к оглавлению
                        titleScreen.addEventListener('click', showContents, { once: true });

                    }, 1500);

                }, 2000); // глитч длится 2 секунды

            }, 1800); // мигание

        }, 400); // пауза перед миганием

    }, 700); // задержка после свайпа
}

function showContents() {
    // Буквы растают
    titleScreen.classList.add('melting');

    setTimeout(() => {
        titleScreen.classList.remove('visible');
        titleScreen.classList.remove('melting');

        // Показываем оглавление
        setTimeout(() => {
            contentsScreen.classList.add('visible');

            // Поочерёдно проявляем пункты
            const items = document.querySelectorAll('.contents-item');
            items.forEach((item, index) => {
                setTimeout(() => {
                    item.classList.add('revealed');
                }, 200 + index * 80);
            });

        }, 300);

    }, 1200);
}

function openChapter(index) {
    if (index < 0 || index >= chapters.length) return;

    currentChapter = index;
    const chapter = chapters[index];

    const numberEl = chapterScreen.querySelector('.chapter-number');
    const titleEl = chapterScreen.querySelector('.chapter-title');
    const textEl = chapterScreen.querySelector('.chapter-text');
    const prevBtn = chapterScreen.querySelector('.nav-prev');
    const nextBtn = chapterScreen.querySelector('.nav-next');

    numberEl.textContent = 'Глава ' + chapter.number;
    titleEl.textContent = chapter.title;
    textEl.innerHTML = chapter.text;

    prevBtn.classList.toggle('inactive', index === 0);
    nextBtn.classList.toggle('inactive', index === chapters.length - 1);

    contentsScreen.classList.remove('visible');

    setTimeout(() => {
        chapterScreen.classList.add('visible');
        chapterScreen.scrollTop = 0;
    }, 300);

    saveState({ lastChapter: index });
}
